USE my_article;
INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('product', '芒市石斛', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/19591715840728616_芒市石斛.png', '中国国家地理标志产品', '<p class="MsoNormal"><strong><span style="color:#333333"><span style="background-color:#ffffff"><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">芒市石斛</span></span></span></span></span></strong></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong>云南省芒市特产，中国国家地理标志产品</strong></span></span></span></span></span></p><p></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">石斛性平、味甘、淡微苦、微寒，归胃、肺、肾经。主治伤中、除痹下气、补五脏劳虚赢瘦、强阴益精，久服厚肠胃。芒市以其自然气候条件，冬无严寒，夏无酷暑，盆坝2边缘的丘陵缓坡冬春有300~700m厚度的逆温层，丰热量、丰沛的雨量、充足的阳光以及茂密的森林和清新2空气，造就了“芒市石斛”特色鲜明、质地优良;质量好，产量高、生长周期短的特点。</span></span></span></span></span></p>', 0, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'chf9rN4dWZHpVUZA', '2024-05-16 14:26:09', '2024-05-16 16:38:41', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
  sort=VALUES(sort), status=VALUES(status), isRecommend=VALUES(isRecommend), readCount=VALUES(readCount),
  album=VALUES(album), address=VALUES(address), coordinate=VALUES(coordinate), mobile=VALUES(mobile),
  openTime=VALUES(openTime), ticketPrice=VALUES(ticketPrice), updateTime=VALUES(updateTime), isDelete=0;
INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('product', '梁河回龙茶', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/13681715841010492_梁河回龙茶.jpg', '云南省德宏傣族景颇族自治州梁河县特产', '<p class="MsoNormal"><strong><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">梁河回龙茶</span></span></span></span></span></strong></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong>云南省德宏傣族景颇族自治州梁河县特产</strong></span></span></span></span></span></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"> </span></span></span></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">回龙茶”因最早兴于梁河县大厂乡回龙寨而得名。梁河县海拔1500~2200米，现存的古茶树有3万余亩，其中树龄千年以上的有1500余株。</span></span></span></span></span></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">梁河县的茶叶历史与人类迁徙繁衍生息息息相关，德昂族是以茶为生“最古老的茶农”，从梁河先民发现茶和种茶食用开始，至今已有上千年历史。梁河“回龙茶”，具有香气高爽、栗香浓郁，滋味醇厚，浓酽而不烈、回甘而不涩、余味悠长。</span></span></span></span></span></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">2013年4月，梁河回龙茶获得国家农业部颁发的中国农产品地理标志认证。</span></span></span></span></span></p>', 0, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, '2FKw1JDtAMGNGkHF', '2024-05-16 14:30:43', '2024-05-16 14:30:43', 0) ON DUPLICATE KEY UPDATE
