INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('product', '德昂酸茶', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/19141715841083395_德昂酸茶.jpg', '藏在深闺人不识，微酸微苦味甘甜', '<p class="MsoNormal"><strong><span style="color:#333333"><span style="background-color:#ffffff"><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">德昂酸茶</span></span></span></span></span></strong></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong>藏在深闺人不识，微酸微苦味甘甜</strong></span></span></span></span></span></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"> </span></span></span></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">酸茶，又称湿茶，古称古茶或沽茶，是我国云南少数民族德昂族和布朗族的传统茶叶制品，它是以云南大叶种鲜叶为原料，采用杀青、揉捻、厌氧发酵等特定的加工工艺制成，具有酸香酸爽等独特品质特征的茶叶。</span></span></span></span></span></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">2022年11月29日，在摩洛哥拉巴特召开的联合国教科文组织保护非物质文化遗产政府间委员会第17届常会上通过评审，将“中国传统制茶技艺及其相关习俗”列入联合国教科文组织人类非物质文化遗产代表作名录，我州芒市“德昂族酸茶制作技艺”作为该项目的子项目成功入选，成为德宏州继傣族剪纸之后第二个入选的非遗项目。</span></span></span></span></span></p>', 0, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'ocZ127fTxmgmSVCm', '2024-05-16 14:31:28', '2024-05-16 14:31:28', 0) ON DUPLICATE KEY UPDATE
