INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('product', '遮放贡米', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/13211715841127830_遮放贡米.jpeg', '中国国家地理标志产品', '<p class="MsoNormal"><strong><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">遮放贡米</span></span></span></span></span></strong></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong>中国国家地理标志产品</strong></span></span></span></span></span></p><p></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">遮放贡米是云南省德宏傣族景颇族自治州芒市的名优农特产品，早在1623年，遮放土司带着玉器、大象、遮放允午村的米等进贡朝廷，受到皇帝喜爱，当即封遮放允午米为“贡米”，每岁进贡，直至清末。1956年，被定为国务院接待外宾的国宴用米之一。</span></span></span></span></span></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">遮放贡米色泽晶莹如珍珠，米饭香醇可口，软筋香甜，粘而不稠，冷不回生，营养丰富，被誉为“净如翡翠白似玉，生自南国举无双”的粮中珍品。</span></span></span></span></span></p>', 0, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'CYzz069rE944tINV', '2024-05-16 14:32:10', '2024-05-16 14:32:10', 0) ON DUPLICATE KEY UPDATE
