INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('product', '蔗糖', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/15711715841187216_蔗糖.png', '云南省重要的传统优势产业', '<p class="MsoNormal"><strong><span style="color:#333333"><span style="background-color:#ffffff"><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">蔗糖</span></span></span></span></span></strong></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong>云南省重要的传统优势产业</strong></span></span></span></span></span></p><p><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong>云南省重要的蔗糖生产基地</strong></span></span></span></span></span></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"> </span></span></span></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">德宏州位于云南省西南边陲，介于东经98°40′~99°43′、北纬22°30′~23°02′之间，西与缅甸接壤，属亚热带季风气候区，气候温和、雨量充沛、日照充足，非常适宜甘蔗种植，特殊的地理位置和优越的地形、气候条件，使得德宏在制糖业的发展上一直保持着喜人成绩和良好势头。</span></span></span></span></span></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">自1958年筹建第一座糖厂以来，已经走过了60多年的发展历程，经过多年的培育，德宏甘蔗种植管理、甘蔗单产、制糖生产水平处于全国、全省前茅，食糖产量占全省25%、全国5%。</span></span></span></span></span></p>', 0, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'dKO8l9lQ0vi4bMSD', '2024-05-16 14:33:09', '2024-05-16 14:33:09', 0) ON DUPLICATE KEY UPDATE
