INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('product', '德宏咖啡', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/18201715841226553_德宏咖啡.jpg', '荣获亚洲咖啡协会的Abody', '<p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong><span style="font-size:20px">德宏咖啡</span></strong></span></span></span></span></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong>获得亚洲咖啡协会的Abody</strong></span></span></span></span></span></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"> </span></span></span></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">德宏是我国最早引进和最适宜咖啡种植的地区之一，早在1893年便从瑞丽市弄贤村引进种植小粒咖啡，德宏咖啡产业在农业种植、生产加工、市场开拓、品牌打造等方面走在前列，被评为中国特色农产品小粒咖啡优势区，享有“中国咖啡之乡”的美誉，拥有中国最大的咖啡种质资源库和中国咖啡工程研究中心，是亚洲咖啡年会的永久举办地。</span></span></span></span></span></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">德宏的咖啡豆品种优良，质优味美，具有“香而不烈、浓而不苦、略带果味”的特质，被国内外咖啡界人士赞誉为“国际上质量最好的咖啡之一”。</span></span></span></span></span></p>', 0, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'tlrhMwEJaZ4wrwgL', '2024-05-16 14:33:48', '2024-05-16 14:33:48', 0) ON DUPLICATE KEY UPDATE
