INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('product', '瑞丽柠檬', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/10761715841240717_瑞丽柠檬.jpeg', '中国国家地理标志产品', '<p class="MsoNormal"><strong><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">瑞丽柠檬</span></span></span></span></span></strong></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong>中国国家地理标志产品</strong></span></span></span></span></span></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"> </span></span></span></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">德宏种植柠檬，当年即开花挂果，一年开三次花，四季结果，第三年进入丰产，平均亩产量达1.5吨—2吨，最高的达4吨多。较国内其他柠檬主产区提前两三年投产，具有发展柠檬反季果的天然优势，是世界上最适宜种植柠檬的地区之一。</span></span></span></span></span></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">瑞丽柠檬主要有云柠一号、尤力克、塔西堤三个品种，均适宜鲜食和加工。经云南农业大学果树实验室测试分析，瑞丽柠檬香精油中柠檬醛的含量高达41%，远高于美国和意大利的含量。</span></span></span></span></span></p>', 0, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'oTYWNctOqTMUCDID', '2024-05-16 14:34:22', '2024-05-16 14:34:22', 0) ON DUPLICATE KEY UPDATE
