INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('product', '德宏涮涮辣', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/10381715841290057_德宏涮涮辣.jpg', '世界最辣的辣椒之一', '<p class="MsoNormal"><strong><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">德宏涮涮辣</span></span></span></span></span></strong></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong>世界最辣的辣椒之一</strong></span></span></span></span></span></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"> </span></span></span></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">涮涮辣，产于我国云南德宏、保山、临沧及缅甸北部的亚热带山区，以德宏的辣味最强，种植面积、产量最高。</span></span></span></span></span></p><p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">涮涮辣，傣语：“嘛苤胀线”，颜色鲜艳，闻之辣味扑鼻，据说，当地的少数民族将它晾干后做调味用，吃的时候只需将它放进汤里涮几下，整锅汤就会辣味十足。如此反复使用，到只剩下辣椒杆时才丢弃，&quot;涮涮辣&quot;因此得名。</span></span></span></span></span></p>', 0, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'g0JgDqH1dBGw3Xem', '2024-05-16 14:34:52', '2024-05-16 14:34:52', 0) ON DUPLICATE KEY UPDATE
