INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '敏格拉芭手镯供应中心', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-04-29/15071714385722721_微信截图_20240429171544.png', '敏格拉芭是翡翠王朝公司旗下专业的翡翠手镯供应中心', '<p class="MsoNormal"><span style="font-size:20px"><strong><span style="letter-spacing:2px">敏格拉芭手镯供应中心</span></strong></span></p><p></p><p><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">敏格拉芭成立于2020年，是翡翠王朝旗下翡翠手镯供应中心。项目扎根中缅翡翠核心产业带--瑞丽，依托翡翠王朝16年深耕翡翠产业资源，以“整合供应链、服务产业链、创造价值链”的品牌发展观，整合上下游产业资源，构建“矿主/工厂/货主到商家”之间的桥梁。多年来始终坚持以商家为中心，以“把利润还给商家”理念，专注为商家提供源头市场一手货源。</span></span></span></p><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/17101715778561530_图片2.png?sign=aeb57c95c7c47f7df9b90703bef35e3f&amp;t=1715778542"/></div><p></p><p><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">敏格拉芭供应链货盘主要以手镯为主，现与缅方相关机构及矿主建立了长期合作关系，拥有手镯的优先采购权，参股平洲20余家手镯加工工厂，累计与近千余高端货主合作，现已建立起稳定的源头货品供应链条，为商家持续提供缅甸一手翡翠手镯。</span></span></span></p><p></p><p><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">敏格拉芭货品种类包含手镯、珠链、挂饰、戒面等市场主流珠宝翡翠消费品，其中自有手镯货盘超过1万条手镯，月均新品逾10000+。通过多年供应经验，已建立完善的货品梯度，从福利品到引流品再到主销品和高货区，产品种类可满足直播销售的全过程。</span></span></span></p>', 50, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, '4wKW0dg6HL3cdBII', '2024-04-29 18:16:05', '2025-08-15 15:18:53', 0) ON DUPLICATE KEY UPDATE
