INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '手镯之家', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-18/18131716020411750_WechatIMG1141.jpg', '珠宝直播翡翠手镯领域标杆品牌', '<p style="text-align:left;" class="MsoNormal"><span style="font-size:20px"><strong><span style="letter-spacing:2px">手镯之家</span></strong></span></p><p></p><p><span style="letter-spacing:2px"><span style="font-size:14px"><span style="line-height:1.75"><span style="color:#3e3a39">手镯之家创立于2020年，背靠翡翠王朝15年来深耕翡翠产业之资源，扎根中缅翡翠核心产业带瑞丽，践行“品质为本，服务领先”的品牌理念，手镯之家已经发展成为珠宝直播翡翠手镯领域的标杆，以优质的产品品质和服务品质引领行业。</span></span></span></span> </p><p size="0" _root="undefined" __ownerid="undefined" __hash="undefined" __altered="false"></p><p><span style="color:#3e3a39"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">手镯之家坚持“专注手镯，只做好货，稳健前行”品牌发展观，以客户为中心，只做缅甸翡翠“源头好货”，倡导诚信透明“阳光服务”，为手镯之家的发展夯实了信任基础，“珠宝玉石直播诚信直播间奖”、“卓越客户服务奖”、“诚信金牌主播”、“抖音热销榜 TOP10”、“抖音回购榜TOP10”……手镯之家赢得了市场口碑，获得了政府、平台和行业的高度赞誉。 </span></span></span></span></p><p size="0" _root="undefined" __ownerid="undefined" __hash="undefined" __altered="false"></p><p><span style="letter-spacing:2px"><span style="font-size:14px"><span style="line-height:1.75"><span style="color:#3e3a39">从优秀到卓越，手镯之家不仅在国内打响了品牌，作为中国顶头部的翡翠手镯销售商，在缅甸，手镯之家也得到了各大矿主、货主的青</span></span></span></span> <span style="letter-spacing:2px"><span style="font-size:14px"><span style="line-height:1.75"><span style="color:#3e3a39">睐，成为缅甸优先级手镯采购商！手镯之家将永葆初心，持续优化产品和服务，用稳健而务实的步伐砥砺前行，向“中国翡翠手镯第一品牌”的目标迈进！</span></span></span></span></p>', 20, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, '1ZVK23Mty7cpDBub', '2024-04-29 18:16:31', '2025-08-15 15:20:16', 0) ON DUPLICATE KEY UPDATE
