INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '云南自由贸易试验区肯发实业有限公司', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/19771749018864584_肯发12.png', '成立于2020年', '<p><span style="line-height:1.75"><span style="letter-spacing:2px"><strong><span style="font-size:18px">云南自由贸易试验区肯发实业有限公司</span></strong></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">云南自由贸易试验区肯发实业有限公司成立于2020年9月30日，并于当年12月22日与瑞丽市人民政府正式签订投资协议，投资建设“中缅(国际)现代农商产业园”项目。公司主要是以进出口商品贸易为主的综合性经营实业公司，从事农、林、牧、水产品的生产、加工、贮藏、运输、销售等。公司还在缅甸设有分支机构，有服务于国际贸易的仓储、物流等设施，还有规模化的农业种植基地。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">中缅（国际）现代农商产业园位于畹町芒满口岸东北侧约2KM，占地1200余亩，计划总投资20亿元以上。着眼沿边经济，立足口岸优势，依托境内外“两种资源、两个市场”，着力打造进出口商品展示交易、落地加工、冷链仓储、公铁联运、商业服务配套中心。目标是将从缅甸进口商品加工升值返销至缅甸及中国内地。同时，积极承接国内东部产业转移，充分发挥产业园区的区位优势。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">园区提供集散落地与加工、采购与分销、企业引入与仓储物流服务，真正实现落地加工、冷链、仓储、物流、供应链于一体的全方位服务。园区以中缅农产品线上线下跨境贸易为依托、落地加工为重点、冷链仓储物流为辅助、现代化产业园发展为支撑，努力打造中缅边境地区规模最大，配置设施最完善的现代化产业园。</span></span></span></p><p></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：冰糖、冰片糖</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>合作意向</strong>：</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">1.提供农副产品落地加工标准厂房；</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">2.提供多样化、多功能仓储物流服务；</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：姜建伟</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：16606933686</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>邮箱：</strong>8361899292@qq.com</span></span></span></p>', 20, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'DzbPTk3Ij97jzTCw', '2025-06-04 14:35:40', '2025-08-15 15:21:10', 0) ON DUPLICATE KEY UPDATE
