INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '瑞丽市金通进出口有限责任公司', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/12071749023168937_金通.png', '成立于2014年', '<p><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:18px"><strong>瑞丽市金通进出口有限责任公司</strong></span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">公司自成立以来一直都致力于开发缅甸及其他国际市场，到2018年正式开展进出口贸易业务。经营范围：国内贸易代理、货物进出口、技术进出口、以自有资金从事投资活动、进出口代理等。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">公司的服务特点是可以延伸到缅甸全境，确保客户货物从采购到运输、安全到达，并及时反馈相关信息给客户，为客户提供一站式服务。</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">公司自经营以来，通过几年的经营及努力，在行业中已树立了良好的口碑。同时公司也在利用自身优势，不断拓展新的业务，为公司的长期发展注入新的活力。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">出口业务：电子产品、塑料编织袋、机械设备、矿山设备、备品配件、化工原料、药剂、农用机械、建筑材料、机电产品、纺织、日用百货等。</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">进口业务：铅锌精矿、锌锭等矿产品。</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>合作意向</strong>：货物进出口代理</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：黄汉邦</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：18313463657</span></span></span></p>', 19, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, '4sO3LBoH4gTMhh7w', '2025-06-04 15:46:31', '2025-08-15 15:21:20', 0) ON DUPLICATE KEY UPDATE
