INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '德宏正信实业股份有限公司', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/18761749019078628_正信1.png', '成立于2014年', '<p><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:18px"><strong>德宏正信实业股份有限公司</strong></span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">德宏正信实业股份有限公司成立于2014年9月11日，注册资本2.77亿元，是一家茧丝绸全产业链公司。公司投资在陇川县章凤镇工业园区建成投产“陇川桑蚕茧精深加工产业化项目”，占地62亩，建有科研大楼1幢，标准厂房4幢，配24组自动缫丝机，具备年产生丝1000吨、丝绵被2万条的能力，是国内最大的生丝生产企业。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">公司采取“政府+公司+基地+农户”的发展模式，打造了境内外政府、公司、农户利益共同体，既保证了公司对优质原料的需求，又最大程度地保障了农户的利益。在德宏州建成25个小蚕基地，发展桑园6万亩；在缅甸北部建立16个小蚕基地，4个烘茧站，发展桑园4万亩。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">公司坚持科技引领发展，与山东农业大学、西南大学、云南省农科院蚕桑蜜蜂研究所等多家高校和科研院所开展技术攻关。在德宏和缅甸北部地区从事蚕桑产业技术指导，科技人才队伍有高级职称10人，初中级职称35人；硕士研究生5人，大专以上学历78人。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：蚕茧</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>合作意向</strong>：</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">1.开展国际合作</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">2.农业种养殖</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：项俊峰</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：15894417416</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>邮箱</strong>：1756440417@qq. com</span></span></span></p>', 18, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, '4oZ5EZekLNhjw0DY', '2025-06-04 14:38:53', '2025-08-15 15:21:29', 0) ON DUPLICATE KEY UPDATE
