INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '瑞丽市大通实业有限公司', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/13741749019212691_4大通.i', '成立于2001年', '<p><span style="font-size:18px"><strong>瑞丽市大通实业有限公司</strong></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">瑞丽大通是一家多元化贸易侨资企业，业务涉及日化、贸易、金融、食品、包装、矿业、物流、餐饮住宿8个板块。公司主要从事中缅进出口贸易，出口商品400余种，年均进出口额约4亿元。大通货场作为旗下物流公司最重要的部门之一，是瑞丽海关的“监管作业场所”，也是中缅一般贸易的主要通道，承载着出口货物申报、确报、转场等功能，被瑞丽海关评为瑞丽首家海关“AA类管理企业”，并通过了海关高级认证，享有进出口货物快速通关的便利条件。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：日用化工品、机电产品、机械设备、电池生产原料、塑料包装制品、食品加工、纺织品、金属及金属矿批发、零售</span></span></span></p><p></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：姚永源</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话：</strong>13988261318</span></span></span></p>', 17, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'YTYaZgSNDbkGI9Rs', '2025-06-04 14:41:15', '2025-08-15 15:21:40', 0) ON DUPLICATE KEY UPDATE
