INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '瑞丽市常春藤贸易有限公司', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/18121749023264891_常晴藤.png', '成立于2017年', '<p><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:18px"><strong>瑞丽市常春藤贸易有限公司</strong></span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">瑞丽市常春藤贸易有限公司成立于 2017 年，主要从事中缅进出口贸易，核心业务对缅出口纺织品。公司深耕缅甸市场，与缅甸服装制造、纺织品批发零售企业建立良好的合作关系，每年进出口贸易额 5亿元。公司的关联企业瑞丽市捷安交通货物运输有限公司，以瑞丽为中心，建立了辐射国内浙江、江苏、福建、广东等省份，对外辐射缅甸仰光、曼德勒等主要城市的物流网络，搭建的“贸易+物流”平台助力中缅跨境合作。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：针织纺品、服装、日用百货</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：胡雪</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：18669285500</span></span></span></p>', 16, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'OpPdTcqt8mnpCtLR', '2025-06-04 15:47:46', '2025-08-15 15:22:08', 0) ON DUPLICATE KEY UPDATE
