INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '德宏天裕生物医药有限公司', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/10131749023288228_医药.png', '成立于2023年', '<p><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:18px"><strong>德宏天裕生物医药有限公司</strong></span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">德宏天裕生物医药有限责任公司成立于2023年，是专注中药材进出口的专业医药公司。依托强大的全球资源网络，公司深耕国际药材贸易领域，与国内外多个优质产区建立稳定合作，严格遵循国际质量标准与规范，精选道地药材。凭借专业的团队，对进出口药材进行全流程质量把控，确保产品安全、有效。业务覆盖缅甸、老挝、越南、泰国等市场，为国内外药企、医疗机构提供优质中药材及专业进出口服务，致力于推动中医药文化在全球的交流与发展，成为国际中药材贸易的领先企业。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：进口中药材</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：黄蕊金</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：13578233582</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>邮箱</strong>：2378891159@qq.com</span></span></span></p>', 15, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'HMjCWgLPHmrszlMC', '2025-06-04 15:49:36', '2025-08-15 15:22:15', 0) ON DUPLICATE KEY UPDATE
