INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '云南保山恒益实业集团有限公司', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/15871749019293529_7恒益.jpeg', '成立于1994年', '<p><span style="font-size:18px"><span style="line-height:1.75"><strong>云南保山恒益实业集团有限公司</strong></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">恒益集团创立于1994年，目前已成长为涵盖能源、国际产能物流、文旅康养三大事业群及农业生鲜、供应链、跨境电商三大事业部的综合性集团。集团现有职工2000余人，带动就业20000多人，自成立以来累计纳税超55亿元，在助学助教、支持农村建设和各项社会公益捐款累计近2亿元。2024年，在云南企业排名中，恒益集团位列云南企业百强第55位，云南高新技术企业百强第26位，云南服务业企业五十强第15位；在非公企业排名中，位列云南省非公企业百强第37位，云南省非公企业服务业二十强第9位，连续4年位列云南省非公企业百强前50位。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：国际物流服务（专线物流、多式联运、陆运、海运、仓储与供应链管理、关务服务）国际贸易服务（进出口贸易服务）矿产品（铁、铜、锡钨、铅锌、金等）农产品（大马士革玫瑰纯露和精油、身体气泡油、洗护沐产品、磨砂膏、面膜、日霜晚霜、中草药、肉牛及牛肉制品、三文鱼）新能源、环保（光伏发电设备、污泥碳化设备）康养产品（中医理疗（针灸、推拿、理疗等）、温泉医康养（法国温泉疗法、芳香疗法、颂钵疗愈、中医疗法及膳食疗法，解决身体亚健康、专病管理、体重管理、运动专训等问题）跨境电商综合服务平台地产旅居（房地产）度假区（东山景区，翡翠博物馆）</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>合作意向</strong>：</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">1.国际物流</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">2.国际贸易</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">3.矿山开发</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">4.跨境电商</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">5.集中式光伏发电</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">6.农业种养殖</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：段正春</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：13887834272</span></span></span></p>', 14, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 't1WclzwvbwO6jCdI', '2025-06-04 14:42:57', '2025-08-15 15:22:25', 0) ON DUPLICATE KEY UPDATE
