INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '缅侨国际文化传播(云南)有限公司', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/19901749019465487_8缅侨.jpg', '成立于2022年', '<p><span style="font-size:18px"><strong>缅侨国际文化传播(云南)有限公司</strong></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">缅侨珠宝以缅甸矿区业务为中心，整合源头供应链，致力于缅甸翡翠、珍珠、彩宝等珠宝品类原料和成品供应。立足于扎实的产业基础，以短视频、直播为桥梁，链接海内外市场，迄今已赢得全网逾500万粉丝的信赖和支持。“选料考究，做工精细，诚信无欺”，缅侨珠宝传承寸氏百年治玉准则与精神，务求“真”字当头，“诚”字为要，真正让每个人买到货真价实的珠宝！缅侨珠宝发展至今集开采、加工、设计、销售为一体，已成为云南翡翠、侨商品牌代表性名片。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：缅甸翡翠、珍珠、红蓝宝石等珠宝品类原料和成品供应</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>合作意向</strong>：</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">1.珠宝玉石直播</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">2.珠宝玉石交易</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">3.供应链整合</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">4.跨境电商</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：杨思展</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：18301626817</span></span></span></p>', 13, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'zfY4v0xAHu1Qu6nJ', '2025-06-04 14:45:39', '2025-06-07 17:23:22', 0) ON DUPLICATE KEY UPDATE
