INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '瑞丽珠宝玉石首饰行业协会', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/10771749019605904_9宝协.png', '成立于1994年', '<p><span style="font-size:18px"><strong>瑞丽珠宝玉石首饰行业协会</strong></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">协会是由从事珠宝玉石研究、生产、加工、销售等方面的单位和个人组成，是珠宝玉石经营和爱好者自己的组织，是具有独立法人资格的非营利性的社会团体组织。业务范围为宣传国家法规和政策，协助政府及职能部门加强对珠宝玉石行业的监督管理，引导会员依法诚信经营，组织参加省内外珠宝展和玉雕比赛，组织开展“神工奖”玉雕比赛、相关培训和学术交流，研究探讨珠宝玉石行业的新情况和新问题。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>主营产品</strong>：珠宝</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>合作意向</strong>：加强与缅甸国家珠宝协会的沟通与交流</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：陈辉</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：0692-4111889</span></span></span></p><p></p>', 12, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'OM3L3T2xPcU0BM4g', '2025-06-04 14:46:57', '2025-08-15 15:21:51', 0) ON DUPLICATE KEY UPDATE
