INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '滇缅公盘盈江翡翠有限公司', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/10051749023503666_滇缅.png', '--', '<p><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:18px"><strong>滇缅公盘盈江翡翠有限公司</strong></span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">滇缅公盘盈江翡翠有限公司翡翠交易平台，是由盈江县县属国有企业盈江恒隆实业有限公司携手成都天府商品交易所共同精心打造的国际化翡翠毛料交易平台。该平台立足盈江独特的地缘优势，致力于推动盈江从传统的“原石交易基地”向集交易、加工、文化旅游为一体的“翡翠产业枢纽”华丽转型，努力打造在国际上极具影响力的翡翠公盘交易中心。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：翡翠</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：申明杰</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：15908820464</span></span></span></p>', 11, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'N3X8bAmT03DCPXnf', '2025-06-04 15:52:12', '2025-08-15 15:22:00', 0) ON DUPLICATE KEY UPDATE
