INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '飞彪助手', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-18/18571716023296648_WechatIMG1163.jpg', '做珠宝玉石生意就用飞彪助手', '<p class="MsoNormal"><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px"><strong>飞彪助手</strong></span></span></span></p><p></p><p size="0" _root="undefined" __ownerid="undefined" __hash="undefined" __altered="false"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">飞彪珠宝直播助手是云南信长科技有限公司旗下的信息化管理软件，云南信长科技有限公司坐落于云南省昆明市五华区学府路690号金鼎科技园内，公司成立于2020年8月，是一家专业致力于计算机软硬件开发及应用，技术咨询、技术服务及技术转让、互联网安全服务、互联网数据服务、信息系统集成服务、信息处理和存储支持服务、互联网信息服务的科技型企业。</span></span></span></p><p></p><p size="0" _root="undefined" __ownerid="undefined" __hash="undefined" __altered="false"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">飞彪供应链管理系统是一款面向珠宝玉石行业拥有独立供应链、直播间内部供应链商户的一体化多操作平台的解决方案，以货品出入库、销售管理、财务结算、客户管理为核心业务，实现了供应链和直播间内部供应链高效的货品流转，助推珠宝玉石商户快速实现运营模式升级。</span></span></span></p><p></p><p size="0" _root="undefined" __ownerid="undefined" __hash="undefined" __altered="false"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">信长科技心怀对技术和珠宝行业的热爱，渴望能以技术在行业内创造客户价值，以获得客户长久的信任是公司的经营理念；提供持续的产品和服务，让客户获得成功是我们的使命;我们坚信以技术驱动珠宝行业提升效率，给行业客户成功带来价值，助力当前的珠宝互联网+营销。</span></span></span></p>', 10, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'uHqonstB5hMPtdj8', '2024-05-15 21:16:57', '2025-08-15 15:20:28', 0) ON DUPLICATE KEY UPDATE
