INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '云南翡翠王朝网络科技有限公司-杨小乖珠宝', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/12581749020065419_15831716021151947_图片1.png', '成立于2022年', '<p><span style="font-size:18px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>云南翡翠王朝网络科技有限公司-杨小乖珠宝</strong></span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">翡翠王朝于2008年创立于中缅边境云南瑞丽，经受了多个市场周期的锤炼，逐步成长为一家稳健且与时俱进的珠宝玉石产业综合服务公司。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">公司立足于瑞丽和佛山平洲，深耕翡翠核心产业带，控股超过20家珠宝相关企业，联合开发多宝之城、益众直播大卖场等专业珠宝市场，共建并运营抖音等三大顶流平台六个珠宝直播基地，孵化出思懿系列、手镯之家、手镯杨小乖等直播团体。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">翡翠王朝秉持“自强不息、共生共荣”的理念和“促进产业共荣、见证璀璨人生”的使命，长期致力于促进翡翠产业的高质量发展和数字化营销探索，以期实现规范化、规模化、品牌化发展。经过十余年不懈奋斗，翡翠王朝公司及创始人杨牧仁荣获“中国改革开放40周年珠宝行业先进企业”和“中国改革开放40周年珠宝行业先锋人物”双项殊荣。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：翡翠、非洲翠</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>合作意向</strong>：供应及销售</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：陈远航</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：18380234420</span></span></span></p>', 10, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'huHfAdroTLDjxMQC', '2025-06-04 14:56:00', '2025-08-15 15:25:57', 0) ON DUPLICATE KEY UPDATE
