INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '云南翡翠王朝网络科技有限公司-敏格拉芭手镯供应中心', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/14021749020490424_5af0d0e9fdecd028d86c1733c081dd92.JPG', '成立于2020年', '<p class="p1"><strong><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:18px">敏格拉芭手镯供应中心</span></span></span></strong></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">敏格拉芭成立于2020年，是翡翠王朝旗下翡翠手镯供应中心。项目扎根中缅翡翠核心产业带--瑞丽，依托翡翠王朝16年深耕翡翠产业资源，以“整合供应链、服务产业链、创造价值链”的品牌发展观，整合上下游产业资源，构建“矿主/工厂/货主到商家”之间的桥梁。多年来始终坚持以商家为中心，以“把利润还给商家”理念，专注为商家提供源头市场一手货源。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">敏格拉芭供应链货盘主要以手镯为主，现与缅方相关机构及矿主建立了长期合作关系，拥有手镯的优先采购权，参股平洲20余家手镯加工工厂，累计与近千余高端货主合作，现已建立起稳定的源头货品供应链条，为商家持续提供缅甸一手翡翠手镯。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">敏格拉芭货品种类包含手镯、珠链、挂饰、戒面等市场主流珠宝翡翠消费品，其中自有手镯货盘超过1万条手镯，月均新品逾10000+。通过多年供应经验，已建立完善的货品梯度，从福利品到引流品再到主销品和高货区，产品种类可满足直播销售的全过程。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：全品类珠宝供应链</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>合作意向</strong>：翡翠、非洲翠全品类珠宝供应链服务</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：柴桑霓</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：18669081375</span></span></span></p>', 9, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, '4e8eZwVlEcaPY5Jo', '2025-06-04 15:01:33', '2025-08-15 15:23:07', 0) ON DUPLICATE KEY UPDATE
