INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '瑞丽样样好国际珠宝有限公司', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/14221749031263534_图片2.png', '成立于2008年', '<p><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:18px"><strong>瑞丽样样好国际珠宝有限公司</strong></span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">瑞丽市样样好电商直播基地，座落于美丽富饶的东方珠宝城--云南瑞丽样样好翡翠文化产业园。基地主体运营公司为：瑞丽市寰宇文化传媒有限公司（以下简称公司）创建于2008年7月，总投资2个亿，是一家集翡翠开采、成品展销、电商孵化、直播运营为一体的综合性企业。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">近年来，随着互联网技术和商业模式的不断推陈出新，加速构造了商业模式和营销方式，“互联网+翡翠”直播销售成为了热门方式，为适应市场发展变化和“网购”消费模式的转变，推动珠宝翡翠行业转型升级公司于2018年开始探索互联网+的道路,两年来在瑞丽市委市政府的关心和领导下，在各级政府及社会各界人士的参与和支持下，公司从众多企业中脱颖而出，在经过层层的线上+线下考核后，相继与全国乃至全世界闻名的互联网平台：阿里巴巴网络技术有限公司、北京快手科技有限公司、北京百度网讯科技有限公司、Bilibili(哔哩哔哩)等签订战略合作协议，合作共建样样好电商直播基地，实现传统企业转型升级。经过数年运营，基地无论从商家规模还是业绩表现，已成长为国内一线电商直播基地。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">基地全国首创的“人、货、场”管理模式是新兴产业中的创新之作，是对“大众创业、万众创新”政策的贯彻和落实。其包含的69规则内容，成为全国各大城市新建直播基地的理论基础。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：样样好国际珠宝城、样样好电商直播基地</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>合作意向</strong>：珠宝玉石销售、珠宝玉石及农产品等其它直播领域</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：蔡凌燕</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：13578282828</span></span></span></p>', 8, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'ehUVn50iwfbm5FNT', '2025-06-04 14:48:29', '2025-08-15 15:22:48', 0) ON DUPLICATE KEY UPDATE
