INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '瑞丽市湃舟网络科技有限公司(婵石珠宝)', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/11581749019742159_15-禅石.jpg', '成立于2016年', '<p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>瑞丽市湃舟网络科技有限公司（品牌：婵石珠宝）</strong></span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">瑞丽市湃舟网络科技有限公司（品牌：婵石珠宝），团队起家2016年创立于中缅边境著名的“翡翠之乡”⸺  云南瑞丽。作为国内中高端翡翠电商销售领先企业，是一家涵盖翡翠珠宝线上线下销售、翡翠供应链、星主播孵化培训的电商公司。从源头选料到售后，各环节都彰显着婵石品质至上的精神，婵石坚持以专业团队多角度在最真实的自然光线下将翡翠自然美、边境文化美通过镜头向全世界分享，将“婵心如水，一生一石”的翡翠独有传承理念传递给每一位翡翠爱好者，直播间所见即所得。历经七载华年，婵石以多种直播模式为一体，开设自营和联营模式，年销售额屡创新高，获得了社会各界、行业及消费者的高度评价，在业内具有极高知名度及美誉度。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：珠宝玉石</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>合作意向</strong>：珠宝玉石供应、销售及直播领域</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：刘田小小、张青健</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：15200388897、18387529491</span></span></span></p>', 7, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'RlAZFTmuxyG8IXy0', '2025-06-04 14:49:57', '2025-08-15 15:22:56', 0) ON DUPLICATE KEY UPDATE
