INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '瑞丽市坤上科技有限公司', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/11561749023549483_坤上.png', '成立于2022年', '<p><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:18px"><strong>瑞丽市坤上科技有限公司</strong></span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">瑞播小程序是瑞丽市坤上珠宝有限责任公司合法运营的一款私域直播SaaS系统，以下将从其功能优势、应用场景、规范管理等维度展开介绍：</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">功能优势</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">• 直播功能强大：支持微信私域珠宝直播、活动直播、教学直播及带货直播等多种形式，在弱网环境下也能保证直播观看的稳定性。</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">• 互动性丰富：提供一键发送评论常用语、直播连麦等功能，可智能互动拉满直播氛围，方便主播极致控场。</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">• 数据安全与分析：直播数据加密更安全，同时能让商家掌握用户实时在线情况，有助于商家根据数据调整直播策略。</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">• 引流获客便捷：具备营销玩法刺激顾客一键转发，实现快速裂变，帮助商家扩大宣传范围，吸引更多潜在客户。</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">应用场景</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">• 珠宝玉石直播：作为瑞丽市重点规范的珠宝玉石直播行业的指定平台之一，许多珠宝商家通过瑞播小程序展示和销售各类珠宝玉石产品。</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">• 其他垂直领域：还涵盖了古玩字画、企业直播带货、金融、医疗、医美、农产品零售等多个垂直领域，为不同行业的商家提供了直播营销的平台。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：瑞播小程序</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>合作意向</strong>：珠宝玉石，古玩字画、企业直播带货、金融、医疗、医美、农产品零售等多个垂直领域的小程序直播。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：周丽梅</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：17708809188</span></span></span></p>', 6, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'GC4EaMwP6gqWTAuu', '2025-06-04 15:53:21', '2025-08-15 15:23:22', 0) ON DUPLICATE KEY UPDATE
