INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '瑞丽德龙集团瑞丽市德龙国际珠宝城有限公司', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/13681749020718671_u=3329748593,1865566221&fm=253&fmt=auto&app=138&f=JPEG.webp', '成立于2012年', '<p><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:18px"><strong>瑞丽德龙集团瑞丽市德龙国际珠宝城有限公司</strong></span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">德龙玉都玉石交易市场位于瑞丽市主城区，占地面积106.25亩，主营翡翠玉石毛料，部分混杂经营成品，以夜市为主。市场月平均收入100万（因市场商户流动性较大，每月收入不等），年平均收入1200万。自2022年11月复工复产以来，为吸引商家回流，市场积极推出减租优惠活动，针对市场内2000余户米柜经营者实行“交三送一 交六送二”活动，针对80余户商铺经营者实行“交八送四 交五送一”活动，经营者可自行选择按季度、半年、一年等方式缴纳租金，充分为广大珠宝玉石经营者创造优越的经营环境。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">截至目前，市场内从业人员约2600人，市场日均人流量6000余人次；米柜共5569米，已租3000余米，出租率约为54%；商铺115间，已租80间，出租率约为70%。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：德龙玉都市场</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>合作意向</strong>：珠宝玉石销售商户场地租赁</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：颜克强</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：13529536692</span></span></span></p>', 5, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'sFxoMuG9cliSugqJ', '2025-06-04 15:06:41', '2025-06-07 17:30:07', 0) ON DUPLICATE KEY UPDATE
