INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '柿果珠宝（瑞丽市）有限公司', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/17121749019847769_18柿果.jpeg', '成立于2024年', '<p><span style="font-size:18px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>柿果珠宝（瑞丽市）有限公司</strong></span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">柿果珠宝作为新兴珠宝品牌，我们致力于以非洲翠为载体，构建从原料溯源到终端销售的全产业链体系，打造高性价比非洲翠珠宝品牌。我们以&quot;让品质玉石走进千家万户&quot;为使命，在传承东方玉文化的同时，探索当代珠宝艺术表达的创新路径。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">在2023年5月柿果珠宝品牌于大理启航，成为国内首批非洲翠产业化运营的探路者。通过不断努力，于2024年3月落地保山龙陵加工厂，实现自主生产体系构建。同年8月总部落户翡翠之都瑞丽。在瑞丽政府的大力扶持下，柿果珠宝业务得到快速发展，于12月启动柿果珠宝瑞丽非洲翠产业园的建设工作。现已初步建成了生产、加工、零售、批发、直播等多层次企业模式。全力与瑞丽直播各团队融合发力，成为了瑞丽合作精神最强的团队之一。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">根植于瑞丽，柿果珠宝将在未来三年内围绕非洲翠产业，构建起以标准化生产加工为目标的加工体系。未来，我们将继续以非洲翠为载体，依托全产业链优势，探索珠宝与文化、艺术的深度联结，致力于成为消费者心中“品质与信赖”的代名词。 </span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">柿果珠宝，玉见中国美。 </span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：非洲翠</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>合作意向</strong>：供应、销售及直播领域</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：彭鑫</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：18306935631</span></span></span></p>', 4, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'uhU3qhwzXZBGTM6A', '2025-06-04 14:51:53', '2025-06-07 17:30:53', 0) ON DUPLICATE KEY UPDATE
