INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '瑞丽市非之翠产业园区运营管理有限公司', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/19001749023663173_非之翠.png', '成立于2025年', '<p><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:18px"><strong>瑞丽市非之翠产业园区运营管理有限公司</strong></span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">瑞丽市非之翠产业园区运营管理有限公司，成立于2025年，运营管理建设瑞丽非洲翠产业园项目，项目用地位于瑞丽市弄莫湖国际文化特色风貌区，项目用地共有7块，总用地面积339517.03㎡（合512.27亩），周边路网已成形，交通便捷。项目发展目标：以非洲翠珠宝文创为产业核心 ， 以 “创新、科技、人文、生态”四元互动机制为特色，结合服务配套， 打造完整的珠宝创业创新 生态体系。实现 “珠宝企业集聚、珠宝产业完善、 珠宝研发领先的技术高端、服务一流和人才高地”的发展目标。总体定位：以建设边境珠宝贸易中心城市为契机，以丰富的非洲翠为基础打造一个集“设计研发、加工制造、商贸展销、文化传播”于一体的宜居宜业的城市珠宝文化创意产业综合体。项目总投资人民币50亿元，项目建设周期24个月，项目建设分段：项目临时公盘已建，标预计2025年7月投入建设、文创园、加工园区在设计中。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：非洲翠文创园区</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>合作意向</strong>：非洲翠供应、销售、直播等所有商户</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：李根伟</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：18788240055</span></span></span></p>', 3, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'FIVV17dfVdmcYkLc', '2025-06-04 15:54:23', '2025-06-07 17:31:33', 0) ON DUPLICATE KEY UPDATE
