INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '德宏州海华珠宝小镇有限公司', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-04/14871749019934599_21-海华珠宝.jpeg', '成立于2008年', '<p><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:18px"><strong>德宏州海华珠宝小镇有限公司</strong></span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">芒市珠宝小镇始建于2008年，占地面积246亩，总建筑面积30万平方米。是一个集翡翠、非洲翠、黄龙玉、红蓝宝、毛料公盘、生产加工、批发零售、文化传播为一体的珠宝产业中心。现有来自东南亚各国及国内各地共300余户商家。三期工程将建设“德宏州游客集散中心”，珠宝小镇将充分发挥珠宝市场作为商品聚集地的龙头作用，提升珠宝经营规模和档次，促进市场向专业化、规范化、标准化、国际化发展，打造文明、规范、有序、和谐市场经营环境，为国内外广大客商购销珠宝提供便利。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：珠宝毛料、成品、加工，美食、文化产品等</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：李敏</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：13120216888</span></span></span></p>', 2, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'fSYVd2RfJEEF5qIU', '2025-06-04 14:53:08', '2025-08-15 15:23:54', 0) ON DUPLICATE KEY UPDATE
