INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '德宏州姐告玉城实业有限责任公司', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-07/17281749288935480_图片1.png', '成立于2000年', '<p><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:18px"><strong>德宏州姐告玉城实业有限责任公司</strong></span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">德宏州姐告玉城实业有限责任公司于2000年12月注册成立，是姐告实施“境内关外”管理政策后，最早进驻姐告边境贸易区的民营企业。公司注册资本3000万元，占地16903平方米，建筑面积11792平方米。市场内经营活动商户达2000余户，其中缅甸籍商户600余户。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">公司集实业投资、物业租赁、市场服务管理、进出口贸易、珠宝玉石、木化石等工艺品的设计、加工、销售、电商孵化、代运营、培训、广告投放、供货中心为一体的现代化民营企业。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">公司下设德宏州姐告玉城珠宝玉石毛料交易市场、德宏州姐告玉城工艺品展厅、德宏州姐告玉城玉石雕刻培训中心、APP电商平台、姐告玉城报关服务中心、主营进出口业务的瑞丽黎昌商贸公司、姐告玉城直播孵化中心、姐告玉城界面中心、姐告玉城跨境电商有限责任公司、瑞丽市玉城珠宝有限责任公司、瑞丽市快淘商贸有限责任公司、德宏州玉城电子商务有限责任公司。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">玉城市场经过20年的培养，在上级部门、领导及商业人士的关心支持和帮助下，现已成为瑞丽人气最旺、交易量最大、线上线下一体的珠宝市场之一，每天来自国内外商人云集在此从事玉石毛料成品交易。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：翡翠原石、翡翠成品</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：舒圆</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：15600003919</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>邮箱</strong>：1369353682@qq.com</span></span></span></p>', 1, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'aeBZWigCWve5fb9d', '2025-06-07 17:35:44', '2025-06-12 14:45:15', 0) ON DUPLICATE KEY UPDATE
