INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '禅石珠宝', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-06-15/18701718423137287_IMG_0528.jpg', '用心讲述每一件翡翠的前世今生，
为每一位消费者甄选陪伴一生的玉翠珠宝。', '<p><span style="line-height:1.75"><strong><span style="font-size:20px"><span style="letter-spacing:2px">禅石珠宝</span></span></strong></span></p><p></p><p> <span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">“婵”寓美好，玉饰佳人</span></span></span></p><p style="text-align:left;" size="1" _root="[object Object]" __ownerid="undefined" __hash="undefined" __altered="false"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">“石”如人生，玉汝于成</span></span></span></p><p style="text-align:left;" size="1" _root="[object Object]" __ownerid="undefined" __hash="undefined" __altered="false"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">婵石珠宝用心讲述每一件翡翠的前世今生，为每一位消费者甄选陪伴一生的玉翠珠宝。</span></span></span></p><p></p><p style="text-align:left;" class="p"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">婵石珠宝（原禅石翡翠）是一家集玉翠珠宝线上线下销售、供应链管理、IP星主播孵化、新媒体营销、商学院培训为一体的珠宝集团公司。</span></span></span></p><p style="text-align:left;" class="p"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">公司下设供应链管理中心、人才孵化中心、品牌管理中心、新媒体运营中心、财务管理中心及行政管理中心，团队规模达千人。广东公司占地约5000㎡，设有高奢会所、实体柜台等珠宝体验空间；云南公司坐拥独栋办公楼，设有员工餐厅、运动休闲、能量补给等舒适办公空间。</span></span></span></p><p style="text-align:left;" class="p"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">禅石珠宝始终坚守“甄选品质珠宝，弘扬玉翠文化”的企业使命，以客户为先、诚信立业、利他共创、创新行远“为经营理念。凭借高服务、高品控和供应链的高质量，成为CCTV报道珠宝品牌；多次受邀参加官方平台年度盛典，荣获“珠宝基地优秀商家”、“年度销冠”、“全球购优秀买手”、“商业化之秀”、“最具专业素质主播”、“最佳短视频内容奖”、“最具价值团队”、“诚信经营奖”、“最佳服务奖”等50+奖项。</span></span></span></p><p style="text-align:left;" class="p"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">功以才成，业由才广。公司贯彻“德才兼备、阳光敬业、创新实干、感恩利他”的人才理念，婵石商学院关注员工成长，通过系统培训，实现个人与企业共同发展。</span></span></span></p><p style="text-align:left;" class="p"></p><p></p><p><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">企业使命：“甄选品质珠宝，弘扬玉翠文化”。</span></span></span></p><p style="text-align:left;" class="p"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">企业愿景：成为消费者信赖、合作伙伴首选、员工幸福、社会认可的企业。</span></span></span></p><p style="text-align:left;" class="p"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">价值观：卓越、诚信、务实、高效。</span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">经营理念：“客户为先、诚信立业、利他共创、创新行远”</span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">服务理念：每一次服务，都比客户的预期多一点</span></span></span></p><p style="text-align:left;" class="p"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">人才理念：德才兼备、阳光敬业、创新实干、感恩利他</span></span></span></p><p style="text-align:left;" class="p"></p><p></p><p><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">发展历程：</span></span></span></p><p style="text-align:left;" class="p"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">2015年：作为首批淘系跨境直播珠宝商家，开启缅甸淘翠的溯源之旅</span></span></span></p><p style="text-align:left;" class="p"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">2016年：聚焦核心业务，在珠宝集散中心——中缅边境瑞丽市成立首家公司。</span></span></span></p><p style="text-align:left;" class="p"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">2020年：企业战略升级，拓展新媒体内容营销、电商直播与品牌矩阵等多元化业务，IP星主播孵化中心持续为行业输送优秀主播，收获全网千万粉丝的认可。</span></span></span></p><p style="text-align:left;" class="p"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">2022年：为满足市场多元化需求，业务拓展至广东，实现“4地经营”；在DTC营运模式下，实体货盘和云仓货盘双轨并行，建立每日上新超3万件的专业玉翠珠宝供应链，与近百个销售团队达成深度合作，实现资源共享、互利共赢。</span></span></span></p><p style="text-align:left;" class="p"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">2023年：正式更名为婵石珠宝，推进“新婵石”的品牌化道路。</span></span></span></p>', 0, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'jEPrcZRJWuOyGwl1', '2024-05-15 21:21:38', '2025-08-15 15:20:36', 0) ON DUPLICATE KEY UPDATE
