INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '绿浪翡翠', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/10121715779426480_图片6.png', '集翡翠原料、矿山采购源头、采购加工生产、品牌运营中心、线下店铺和线上电商销售为一体的综合性翡翠珠宝企业', '<p size="1" _root="[object Object]" __ownerid="undefined" __hash="undefined" __altered="false"><span style="line-height:1.75"><strong><span style="font-size:20px"><span style="letter-spacing:2px">绿浪翡翠</span></span></strong></span></p><p></p><p><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">绿浪翡翠是云南绿浪珠宝玉器有限公司旗下品牌，成立于2011年，集翡翠原料、矿山采购源头、采购加工生产、品牌运营中心、线下店铺和线上电商销售为一体的综合性翡翠珠宝企业。</span></span></span></p><p></p><p size="1" _root="[object Object]" __ownerid="undefined" __hash="undefined" __altered="false"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">绿浪秉承着诚信做人、踏实做事的原则，打造了一支像翡翠一样温润、柔和、平衡的团队；有高度的职业操守，有严格的品质把控，有贴心的售后服务，立志将优质翡翠带给每一位消费者，成为新一代互联网翡翠珠宝商，以传播翡翠玉文化、传播中国传统文化为己任，让翡翠走向全世界。</span></span></span></p><p></p><p size="1" _root="[object Object]" __ownerid="undefined" __hash="undefined" __altered="false"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">绿浪翡翠曾获得2014年度云南省珠宝玉石文化促进会副会长单位、云南省珠宝玉石文化促进会 2016-2017年度诚信单位、荣获2019年瑞丽市人民政府 《2019瑞丽市珠宝互联网直播销售优秀团队奖》和《最具专业素质主播奖》、淘宝官方评为珠宝类前十优质商家、淘宝官方珠宝直播基地头部商家 、淘宝官方连续157期评为金牌卖家、珠宝直播行业排名前十等奖项。</span></span></span></p>', 0, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'Ho7OsHnDcD1zsSHd', '2024-05-15 21:23:33', '2025-08-15 15:20:44', 0) ON DUPLICATE KEY UPDATE
