INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '太美丽珠宝', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-30/18231717052526557_WechatIMG108.jpg', '珠宝玉石直播头部品牌', '<p style="text-align:left;" class="MsoNormal"><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:20px"><strong>太美丽珠宝</strong></span></span></span></p><p></p><p><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">云南太美丽珠宝有限公司位于中缅边境的翠玉之都--瑞丽。成立于2010年，是中国珠宝玉石行业+互联网领域的领军品牌。</span></span></span></span></span></p><p></p><p style="text-align:left;" class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">在这14年间，太美丽珠宝立足缅甸源头，与缅甸各大矿坑携手合作，实现生产销售一体化。随着互联网兴起，依托互联网平台，带领主播团队100多人在云南、广东、四川、河南、江苏等省开设了直营店或联营店，并常年为150多家实体店、会所、优秀微商团队供货，真正做到多品牌的高质量、批发的低价格，曾多次荣获珠宝类电商奖项。</span></span></span></span></span></p>', 0, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'AvZIVS2otjEiquQx', '2024-05-30 15:02:25', '2025-08-15 15:20:53', 0) ON DUPLICATE KEY UPDATE
