INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '禅石珠宝', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-06-15/16091718436290736_IMG_0528.jpg', '用心讲述每一件翡翠的前世今生，为每一位消费者甄选陪伴一生的玉翠珠宝', '<p></p><div class="media-wrap image-wrap float-left" style="float:left"><img class="media-wrap image-wrap float-left" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-06-15/16161718436304578_IMG_0528.PNG?sign=9bb5651f46f4559bcf1b4911fd2839f7&amp;t=1718436285"/></div><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-06-15/15941718436321628_IMG_0529.PNG?sign=2cfe8ff5013eeeb868fa37592e01cc56&amp;t=1718436302"/></div><p></p>', 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, '5Eo1dVq6bW32vflj', '2024-06-15 15:26:42', '2025-06-04 14:33:09', 0) ON DUPLICATE KEY UPDATE
