INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '盈江县政助农业开发有限公司', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-12/19741749710377100_盈江.png', '成立于2014年', '<p><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:18px"><strong>盈江县政助农业开发有限公司</strong></span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">盈江县政助农业开发有限公司成立于2014年7月，是一家国内外的侨企；公司以公司＋基地＋技术创新的发展模式；公司主要以种植、养殖为主，现已经注册了两个商标，分别为《巨石关》和《孟乃河》。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">公司在2008年为响应盈江县政府的号召，在缅甸克钦邦孟像洋中缅边境线上以替代种植方式，公司自投方式和联营合资方式，种植低海拔(220米)热带作物：橡胶和香焦，总面积约27000亩，到目前橡胶种植管护已有15年。现在已具备开割条件，长势非常喜人。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">公司2009年同时在国内董事长施正助家乡（云南省，德宏州，盈江县，昔马镇华侨之乡）投资种植高海拔(1600米至2580米)冷带作物。红花油茶、草果、药用红豆杉、山茶，棕包，林下中药材等总面积5200亩(混种))连片，区域13200余亩，已种植15年，红花油茶、草果、药用红豆杉已大量投产，长势非常喜人。在2014年成立了盈江县政助农业开发有限公司，公司以个体经营珠宝玉石盈利维持公司国内外的农业基地发展。公司一边在发展事业，一边不忘回报社会，回报家乡，感党恩，捐资助学，积极参于国家脱贫攻坚，疫情防控等，社会各种公益活动，近二十多年期间先后在地方社会公益事业上捐资625万多元。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">公司通过近几年的发展，种植的高山红花油茶已挂果投产，以《孟乃河》注册商标生产了高山生态的侨香红花油茶油产品；公司的草果，药用红豆杉也已大量投产，由其在2200至2400米高海抜种植旱地草果，红豆杉，红花油菜，棕包，山茶，林下中药材等总结了一套成熟的高海拨种植技术，欢迎各界朋友前来实地考查后，洽谈合作再加大开发及深加工等，一起合作愉快再共赢</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营</strong>：侨香红花油茶油；药用红豆杉；香蕉；橡胶；草果；山茶；棕包。</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>合作意向</strong>：农业种植与开发、农业技术咨询服务、农副产品加工、销售、畜禽养殖、销售、对外贸易经营、货物进出口、通用仓储服务；</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：施正助</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：13578205665</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>邮箱</strong>：905838688@.qq.com</span></span></span></p>', 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, '5Y1EGl6T3zfre8Zx', '2025-06-12 14:42:14', '2025-08-15 15:24:24', 0) ON DUPLICATE KEY UPDATE
