INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('brand', '德宏丰华进出口贸易有限公司', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2025-06-12/14081749710663895_图片1.png', '成立于2022年', '<p><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:18px"><strong>德宏丰华进出口贸易有限公司</strong></span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px">公司成立于2022年，办公地点在云南省德宏州盈江县平原镇滨江路盈江花园小区6-5-502。公司自成立以来，主要从事货物进出口，技术进出口，国内贸易代理，木材、薪柴销售，珠宝首饰批发，林业产品销售;家具销售;办公设备销售，机械设备销售，建筑材料销售，农副产品销售:五金产品批发，文具用品批发，日用品批发，电子产品销售，工艺美术品及收藏品批发，地产中草药(不含中药饮片)购销，包装服务，劳务服务等各种进出口贸易经营活动。目前，公司在各级领导或相关部门的大力支持和关心下，现已成为盈江乃至全州相关物品进出口贸易规上企业。</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>公司主营：</strong>货物、技术进出口，矿产（石）、木材(木炭)进口销售，珠宝玉石、办公设备、机械设备、建筑材料销售，境外农副产品种植和销等各种进出口贸易经营活动</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>合作意向：</strong>货物、技术进出口，矿产（石）、木材(木炭)进口销售，境外农副产品种植和销等各种进出口贸易经营活动</span></span></span></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>联系人</strong>：段忠敬</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>电话</strong>：17708803333</span></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>邮箱</strong>：1182714060@qq.com</span></span></span></p>', 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'ilCb134PgspQV9aQ', '2025-06-12 14:44:25', '2025-08-15 15:25:26', 0) ON DUPLICATE KEY UPDATE
