INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('market', '多宝之城', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-04-30/11121714463882498_微信截图_20240430155754.png', '瑞丽最大的珠宝翡翠“线上+线下”成品交易市场', '<p class="MsoNormal"><strong><span style="background-color:#ffffff"><span style="color:#000000"><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">多宝之城</span></span></span></span></span></strong></p><p><strong><span style="background-color:#ffffff"><span style="color:#000000"><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:16px">瑞丽最大的珠宝翡翠“线上+线下”成品交易市场</span></span></span></span></span></strong></p><p></p><p><span style="line-height:1.75"><span style="font-size:14px"><span style="letter-spacing:2px">“美玉出多宝、真玉在多宝、买玉到多宝”！</span></span></span></p><p></p><p><span style="line-height:1.75"><span style="font-size:14px"><span style="letter-spacing:2px">多宝之城地处中缅边境最大的口岸城市--瑞丽，以沿边地区数字经济特色产业园的模式进行打造，通过“线上线下”双驱动，将玉石产业、电商经营和文旅产业融合发展，形成集互联网直播、珠宝市场、仓储、质检、物流、IP孵化等线上线下多功能服务，和多样化配套设施为一体的新业态商业综合体。。</span></span></span></p><p></p><p><span style="font-size:14px"><span style="letter-spacing:2px"><span style="line-height:1.75">多宝之城距离姐告经济开发区1.5公里，四面连接城区主干道，配套成熟、设施完善、功能划分明确，设有<strong>吉祥厅、如意厅、荣华厅、中缅胞波街</strong>四个大厅的翡翠成品交易市场以及瑞丽珠宝翡翠博物馆、中缅翡翠大厦、镶嵌一条街等。</span><span style="color:#000000"><span style="background-color:#ffffff">现拥有近万余中缅商家，汇聚缅甸源头好货</span></span></span></span></p><p style="text-align:justify;text-indent:2em;" size="2" _root="[object Object]" __ownerid="undefined" __hash="undefined" __altered="false"></p>', 100, 1, 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, '45EpEWUNwHkZLWiP', '2024-04-30 15:58:14', '2024-05-18 15:23:11', 0) ON DUPLICATE KEY UPDATE
