INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('market', '样样好珠宝基地', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/12691715777416936_样样好.jpg', '直播不夜城', '<p style="text-align:justify;" class="p" align="justify"><strong><span style="background-color:#ffffff"><span style="color:#000000"><span style="line-height:1.75"><span style="font-size:20px"><span style="letter-spacing:2px">样样好珠宝基地</span></span></span></span></span></strong></p><p><strong><span style="background-color:#ffffff"><span style="color:#000000"><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:2px">直播不夜城</span></span></span></span></span></strong></p><p></p><p><span style="color:#000000"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">瑞丽市样样好国际珠宝城成立于2008年，深耕“中国珠宝玉石直播第一城”“中缅翡翠源头第一站”瑞丽多年，以诚信立身，以推广玉文化为己任。经过多年发展，公司不断发展壮大，并紧跟时代风口，于2017年成立样样好电商基地。样样好珠宝直播基地有6000多个摊位，拥有全国独立直播间最多的直播基地和种类齐全的供货商，为全国300多家实体店供货，累计服务批发加盟商和零售客户达100万人次，日销达1000万元，从业人员数万人，年交易额近60亿元。</span></span></span></span></span></p><p></p><p><span style="color:#000000"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">“样样好”品牌获中国著名品牌、云南省著名商标、中国珠宝玉石首饰行业放心示范店等称号。欢迎热爱珠宝的您，走进“边、情、绿、宝”的瑞丽，到样样好直播电商基地欢乐购，感知鲜活的现场，共享奇石盛宴，探寻神秘的珠宝文化。</span></span></span></span></span></p>', 30, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'ZarviFLosksZQcBP', '2024-05-15 20:51:21', '2024-05-16 16:18:23', 0) ON DUPLICATE KEY UPDATE
