INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('market', '盈江翡翠公盘', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/11561715777854694_图片1.png', '中国翡翠毛料第一城', '<p style="text-align:justify;" class="p" align="justify"><strong><span style="background-color:#ffffff"><span style="color:#000000"><span style="line-height:1.75"><span style="font-size:20px"><span style="letter-spacing:2px">盈江翡翠公盘</span></span></span></span></span></strong></p><p style="text-align:justify;" class="p" align="justify"><strong><span style="background-color:#ffffff"><span style="color:#000000"><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:2px">中国翡翠毛料第一城</span></span></span></span></span></strong></p><p></p><p style="text-align:justify;" class="p" align="justify"> <span style="background-color:#ffffff"><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">在二十世纪六十年代的时候，缅甸政府将所有矿产资源收为国有，于1964年3月开始举办翡翠玉石毛料公盘。盈江距缅甸北部盛产翡翠玉石的圣地帕敢仅250公里，从清朝初年至今，盈江一直是是中国距缅甸翡翠玉石产地最便捷的口岸，尤其是2010年缅甸公盘迁至内比都后，翡翠毛料从缅甸公盘进入中国境内的陆路距离缩短了400多公里，同时是中国进口翡翠毛料的必经口岸。</span></span></span></span></span></p><p></p><p><span style="background-color:#ffffff"><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">２００９年１月11日，２００多吨翡翠玉石毛料亮相盈江首届翡翠玉石毛料公盘市场，盈江成为继平洲后中国规模第二的翡翠公盘。自2009年盈江举办首届翡翠玉石毛料公盘交易至2020年7月，已成功举办60届，有3万多吨玉石毛料进场参标，成交额达20亿元。</span></span></span></span></span></p><p></p><p><span style="background-color:#ffffff"><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">那怎样才能在翡翠公盘竞标呢？进入标厂方式是通过会员证进入，办理会员证必须持有会员证的担保人进行担保。同时会费一年一缴（当年会费没有缴纳的会员不能进入标厂）即可，在公盘期间精挑细选的选中原石，精打细算的填好投标单，分编码投入相应的箱子中，就可以离开标厂，开标后，如果标中，会有工作人员电话或者短信联系标中者打款提石。</span></span></span></span></span></p><p></p><p><span style="background-color:#ffffff"><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">盈江不仅具有较好的毛料基础市场，还勇于探索新的方式突围，比如与直播的结合。2020年7月10日-12日的公盘，吸引了淘宝、快手、微拍堂、玩物得志、天猫、拼多多等直播平台进场，全部通过线上直播的模式进行销售，这是全国首次全国翡翠玉石毛料线上公盘。</span></span></span></span></span></p><p></p><p><span style="color:#000000"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">盈江公盘的举办，重新点燃了早已殒没的盈江赌石文化，将盈江重新列入云南翡翠原石口岸的行列，为盈江这几年的经济和玉石文化发展注入了鲜活的血液。</span></span></span></span></span></p><p style="text-align:justify;" class="p" align="justify"><br/></p>', 20, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'IVmsCZonfU7gyDps', '2024-05-15 20:57:39', '2024-05-16 16:19:36', 0) ON DUPLICATE KEY UPDATE
