INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('market', '姐告玉城', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/19921715776804949_玉城.jpeg', '缅甸翡翠原石首站', '<p class="MsoNormal"><strong><span style="background-color:#ffffff"><span style="color:#000000"><span style="line-height:1.75"><span style="font-size:20px"><span style="letter-spacing:2px">姐告玉城</span></span></span></span></span></strong></p><p><strong><span style="background-color:#ffffff"><span style="color:#000000"><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:2px">缅甸翡翠原石首站</span></span></span></span></span></strong></p><p></p><p><span style="color:#000000"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">1998年3月，缅甸政府正式开通其唯一的翡翠陆路出口通道——与瑞丽姐告一街之隔的木姐市，允许翡翠毛料以边贸方式进入瑞丽，姐告成为翡翠毛料进入中国的首站；据海关统计表明，缅甸年产翡翠毛料约6000吨流入我国，从瑞丽进入就占到了4000吨。此外，姐告边境贸易区成为云南省第一个实行“境内关外”特殊管理模式的边贸特区，免税政策结合源头价格，很多翡翠原料价格甚至比缅甸公盘还要便宜很多。不仅吸引国内翡翠业的商家都会定期来姐告挑货批货，也吸引周边很多国家如缅甸、斯里兰卡、泰国等珠宝商家带着翡翠、红蓝宝市场交易。</span></span></span></span></span></p><p></p><p><span style="color:#000000"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">姐告玉城是由德宏州姐告玉城实业公司在2000年初投资创建，最开始以批发零售翡翠毛料为主的市场，后又拓展翡翠成品市场；城每天80%的交易都产生在早上的7点到12点，所以又被成为姐告早市，与德龙夜市齐名；玉城鼎盛时期具有商铺和临时货摊千余家，从事玉石生意的人员超越万人，是中国最成熟、最大的玉石交易市场之一。</span></span></span></span></span></p><p></p><p><span style="color:#000000"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">当疫情的阴霾笼罩，姐告玉城被按下了暂停键。然而，时光不会停滞，希望从未远离。如今，随着市场的逐步开放，姐告玉城犹如沉睡后觉醒的雄狮，它即将再次焕发出耀眼的光芒。我们坚信，它必将越来越好，那些曾经的荣光必将重新闪耀在这片土地上。让我们一同期待姐告玉城的华丽归来，期待它再次成为那璀璨夺目的玉石圣地！</span></span></span></span></span></p>', 10, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'uBWueatjbPkzozle', '2024-05-15 20:41:14', '2024-05-16 16:20:01', 0) ON DUPLICATE KEY UPDATE
