INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('market', '瑞丽珠宝街', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/14821715776213617_11.png', '中华翡翠第一街', '<p style="text-align:left;" size="1" _root="[object Object]" __ownerid="undefined" __hash="undefined" __altered="false"><strong><span style="background-color:#ffffff"><span style="color:#000000"><span style="font-size:20px"><span style="line-height:1.75"><span style="letter-spacing:2px">瑞丽珠宝街</span></span></span></span></span></strong></p><p><strong><span style="background-color:#ffffff"><span style="color:#000000"><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:2px">中华翡翠第一街</span></span></span></span></span></strong></p><p></p><p><span style="color:#000000"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">自上个世纪九十年代起，瑞丽市大力打造“东方珠宝城”的品牌，90后代初瑞丽市政府开放了此地，划出了一条街，构成这个以翡翠成品买卖为主的综合性珠宝买卖商场，这就是最开始的珠宝步行街。</span></span></span></span></span></p><p></p><p><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="color:#000000">珠宝步行街建成于1993年，在笔直的步行街上分布着86家珠宝店，后来在主街的两侧兴建了珠宝商场和其他珠宝店，整个步行街大大小小的珠宝店不下两百个，算上商场柜台则超过千个，是</span><span style="color:#191919">东南亚重要的珠宝集散中心</span>，<span style="color:#000000">吸引了千千万万前来创业的珠宝人员。</span></span></span></span></span></p><p></p><p><span style="color:#000000"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">曾经，瑞丽珠宝街如一颗璀璨明珠，闪耀着无尽的光芒。然而，如今时光流转，它虽已渐渐没落，但它往昔的荣光却并未消散。它就像一位智慧的老者，虽历经沧桑，却用自己过去的辉煌经验，默默地指引着瑞丽新的市场不断前行与发展。</span></span></span></span></span></p>', 0, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'VbN5dZ8L12yOoUvM', '2024-04-30 15:58:51', '2024-05-16 16:20:43', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
