  album=VALUES(album), address=VALUES(address), coordinate=VALUES(coordinate), mobile=VALUES(mobile),
  openTime=VALUES(openTime), ticketPrice=VALUES(ticketPrice), updateTime=VALUES(updateTime), isDelete=0;
INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('market', '德龙夜市/玉都', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-30/15081717039762285_德龙玉都.png', '世界上最贵的地摊', '<p style="text-align:justify;" class="p" align="justify"><strong><span style="background-color:#ffffff"><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:20px"><span style="color:#000000">德龙夜市/玉都</span></span></span></span></span></strong></p><p style="text-align:justify;" class="p" align="justify"><strong><span style="background-color:#ffffff"><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:16px"><span style="color:#000000">世界上最贵的地摊</span></span></span></span></span></strong></p><p style="text-align:justify;" class="p" align="justify"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"> </span></span></span></p><p style="text-align:justify;" class="p" align="justify"><span style="color:#000000"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">提起赌石相玉文化就必须得好好认识一下德龙国际珠宝城。这里是名副其实的“中国翡翠毛料第一站”，世界上最昂贵的地摊。冒险者的天堂，一刀穷一刀富的发生地。</span></span></span></span></span></p><p style="text-align:justify;" class="p" align="justify"><span style="color:#000000"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">因为翡翠的特性和皮壳包裹，即便最先进的仪器也无法检测毛料的好坏，而在黑暗的环境下，通过强光灯照射，毛料表皮的“苍蝇翅”、“藓”，内部的色带、裂纹、絮状物等特征，比在明亮环境下更加明显，便于人们辨别。</span></span></span></span></span></p><p style="text-align:justify;" class="p" align="justify"><span style="color:#000000"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">德龙珠宝夜市依托于德龙国际珠宝城，2014年开设夜市，与传统市场模式不同，德龙夜市是地摊模式；所以每当夜幕降临，一块塑料布、几块翡翠毛料，商户席地而坐，铺满各种各样的翡翠以及其它宝石，而看客则持强光手电在摊位上对原石进行观察挑选，原石买卖买定离开手，可以选择在夜市专门从事原石切割的店铺切开，料“切涨”以后则燃放烟花，全城同庆，而德龙夜市上空，几乎每天都看得到烟花，德龙夜市逐渐成为是瑞丽江岸边一颗最闪耀的夜明珠。</span></span></span></span></span></p><p style="text-align:justify;" class="p" align="justify"><span style="color:#000000"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">而随着业务摊位的稀缺，原有夜市位置已满足不了众多的商户，将原本夜市搬迁至新址并取名为德龙玉都，也从原本的只做毛料夜市拓展到早市、从只做毛料到成品市场，成为综合性、一体性的翡翠交易市场。</span></span></span></span></span></p>', 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, 'eEUBfZgtiIbF80DK', '2024-05-30 11:29:08', '2024-05-30 11:29:08', 0) ON DUPLICATE KEY UPDATE
