INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('jewelry', '手镯', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-04-30/15881714463744852_ad968e3ff999fbb59bed765267dd5d98e22d43c43e9a8-IWRLxE_fw1200.png', '手镯是戴在人手腕上的环形装饰品', '<p style="text-align:left;" size="1" _root="[object Object]" __ownerid="undefined" __hash="undefined" __altered="false"><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">手镯，亦称“钏”、“手环”、“臂环”等，是一种戴在手腕部位的环形装饰品。</span></span></span></span></p><p><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">手镯由来已久，起源于母系社会向父系社会过渡时期。据有关文献记载，在古代不论男女都戴手镯，女性作为已婚的象征，男性则作为身份或工作性质的象征。在古代社会，人们还认为戴手镯可以辟邪或碰上好运气。</span></span></span></span></p><p></p><p> <span style="color:#000000"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong><span style="font-size:16px">1、福镯/圆条</span></strong></span></span></span></p><p><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">内径圆，外圈圆。这种镯子极为经典，流传已久，讲究厚条，庄重正气。福镯适合所有女士佩戴。手镯圆润饱满，外圆、内劲圆、环圆可谓是三圆合一，象征着事业和生活都圆圆满满，佩戴在手腕上，可显出女性的温婉气质，也可保平安，是佩戴收藏的首选。</span></span></span></span></p><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/10541715842497593_7.png?sign=f6843854ec9ce4fb106ddb823785e7af&amp;t=1715842478"/></div><p></p><p><span style="color:#000000"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong><span style="font-size:16px">2、平安镯</span></strong></span></span></span></p><p class="MsoNormal"><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">内圈扁，外圈圆，条杆从弓形到半圆不等，内圈磨平，称平安镯，也叫做扁口镯，是现在市面上90%以上的镯子式样。内圈贴腕，上手度很好；象征着吉祥平安，爱情长久，婚姻幸福；根据条杆的宽窄和凸缓，可再细分为宽条、窄条、缓鞍和凸鞍等类型。</span></span></span></span></p><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/19231715841794580_11111.png?sign=92131a3049d2b908bcb6a7bd8a5bbe8c&amp;t=1715841775"/></div><p style="text-align:left;text-indent:2em;" class="MsoNormal"></p><p><span style="color:#000000"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong><span style="font-size:16px">3、翡翠贵妃镯</span></strong></span></span></span></p><p class="MsoNormal"><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">内圈扁，外圈圆，条杆从弓形到圆形不等，贵妃手镯即椭圆形手镯，椭圆形状更接近人手腕的形状，因此更容易佩戴，而且不容易破碎，更重要的是由于带上去显得手更加纤细、美丽，寓意富贵安康，祈福吉祥，因而十分受到广大女性的喜爱。</span></span></span></span></p><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/18831715841858819_2222.png?sign=3e21a2ebe7b83c4fb462cdc7b98ed586&amp;t=1715841840"/></div><p style="text-align:left;text-indent:2em;" class="MsoNormal"></p><p><span style="color:#000000"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong><span style="font-size:16px">4、美人镯</span></strong></span></span></span></p><p style="text-align:left;" class="MsoNormal"><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">是圆镯的分支，内圈外圈均为圆形条杆圆，但对比圆条条杆直径细，基本上是镯子的一半到三分之一，精致小巧，胜在娇俏灵动，很有少女感；寓意温婉柔情，和谐美满。</span></span></span></span></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/14021715841942464_1.png?sign=55508481894bb0c80fe690f9b9808541&amp;t=1715841923"/></div><p style="text-align:left;text-indent:2em;" class="MsoNormal"></p><p><span style="color:#000000"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong><span style="font-size:16px">5、叮当镯</span></strong></span></span></span></p><p style="text-align:left;" class="MsoNormal"><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">也称为鸳鸯镯，由同一料子做出来的两只细长的手镯，厚度在6mm以下，一般叠戴在一起，手镯碰撞出叮当声，这也是叮当镯的由来。</span></span></span></span></p><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/18641715841986606_2.png?sign=e346c2eb479308887bf3989642a8283e&amp;t=1715841967"/></div><p style="text-align:left;text-indent:2em;" class="MsoNormal"></p><p><span style="color:#000000"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong><span style="font-size:16px">6、方镯</span></strong></span></span></span></p><p style="text-align:left;" class="MsoNormal"><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">整体呈方形，内外皆平，内外圈是圆形，镯身为方形看起来端庄大气，适合手腕便瘦的人，寓意规矩大气。</span></span></span></span></p><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/12791715842025053_3.png?sign=bfb5339c19b7907abef0be674dde3b49&amp;t=1715842006"/></div><p style="text-align:left;text-indent:2em;" class="MsoNormal"></p><p><span style="color:#000000"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong><span style="font-size:16px">7、麻花镯/绞丝镯</span></strong></span></span></span></p><p style="text-align:left;" class="MsoNormal"><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">麻花镯的特点是手镯的条杆是成麻花状的，条杆以圆条为主。麻花镯虽然是翡翠手镯里面的一个重要种类，但是在市场里面却不怎么经常见到，很多人在购买的时候也不会选择购买，麻花镯之所以会出名，主要是依靠宋美龄，宋美龄的麻花镯，据说现在的估价已经在两个亿的人民币了，在国际上也非常的出名。</span></span></span></span></p><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/13041715842056306_4.png?sign=6fef90f5adec0d0417eebd3988421ab7&amp;t=1715842037"/></div><p style="text-align:left;text-indent:2em;" class="MsoNormal"></p><p><span style="color:#000000"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong><span style="font-size:16px">8、工镯</span></strong></span></span></span></p><p style="text-align:left;" class="MsoNormal"><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">工镯的贴点是形状各异，款式众多，但各式工镯都有一个共同特点就是雕工精湛。各式工镯的出现，虽然是为了弥补翡翠的瑕疵，但对手镯进行雕刻就是出于对美的追求，而且经过雕刻，各种吉祥寓意赋予在手镯上面，将不完美变成了完美，赋予了手镯灵魂。工镯上的各类雕刻寓意丰富，极具东方韵味，非常适合内心丰富的女性佩戴，一款好的工镯，反应的不仅是玉雕师工艺，还是佩戴者的审美与品位的体现。</span></span></span></span></p><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/12801715842101968_5.png?sign=b4dc1741a5df55af0475fe4a82a2590a&amp;t=1715842083"/></div><p style="text-align:left;" class="MsoNormal"><span style="color:#000000"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong><span style="font-size:16px">9、镶金镯</span></strong></span></span></span></p><p style="text-align:left;" class="MsoNormal"><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">在中国传统文化中,金和玉象征高贵与纯洁,一如诗仙李白所赞“金樽清酒斗十千,玉盘珍馐值万钱”。金镶玉象征“金玉良缘”,预示着有情人终成眷属。金与玉结合的翡翠手镯，既有玉温润细腻又有金色流光溢彩，一般用于修复手镯、弥补瑕疵部分。展现另一番灵气。</span></span></span></span></p><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/14221715842132042_6.png?sign=ed49e59665855eae7f7a6226a51d8ff8&amp;t=1715842113"/></div><p style="text-align:center;"></p><p style="text-align:left;" size="0" _root="undefined" __ownerid="undefined" __hash="undefined" __altered="false"><strong><span style="color:#191b1f"><span style="background-color:#ffffff"><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:16px">不同的翡翠手镯适合的人也各不相同，戴对了才能尽显奢华与尊贵，爱美的你一定不要选错了！</span></span></span></span></span></strong></p>', 10, 1, 0, 118, NULL, NULL, NULL, NULL, NULL, NULL, 'mOiamZ7fVI0x67HI', '2024-04-30 15:56:37', '2024-05-16 16:12:48', 0) ON DUPLICATE KEY UPDATE
