  album=VALUES(album), address=VALUES(address), coordinate=VALUES(coordinate), mobile=VALUES(mobile),
  openTime=VALUES(openTime), ticketPrice=VALUES(ticketPrice), updateTime=VALUES(updateTime), isDelete=0;
INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('jewelry', '珠链', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/18761715845208668_WechatIMG70.jpg', NULL, '<p><span style="color:#000000"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">翡翠手串是中华玉文化、珠串文化与佛教的结缘，最初是流行于清代上层社会，清朝时，后宫嫔妃们都崇佛、信佛 ，后宫的殿堂内都辟有许多佛堂，妃子们多以诵经念佛来度过无聊寂寞的宫廷生活。中国古代民间都有母凭子贵的说法，更别说皇宫了，所以后宫嫔妃们将手串中的每颗翠珠称为子，寓意希望得到皇帝宠幸而飞黄腾达。</span></span></span></span></span></p><p class="MsoNormal"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="color:#000000"><span style="background-color:#ffffff">一块翡翠原石，基本上是先考虑出手镯，</span></span>翡翠珠链是最耗费原料的品种，而且对原石的要求很高，很多商家都不愿意把最好的原料用于制作珠链。因此，高品质的珠链可遇不可求，并且都价值不菲，收藏价值及升值空间也非常大，成为很多翡翠收藏家的首选。</span></span></span></p><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/10611715845255780_be888738-1cb8-4bed-b5d4-df4e2693ba71.jpg?sign=fe7d753c27831a6d93c177f462449f95&amp;t=1715845236"/></div><p></p><p><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="color:#000000"><span style="background-color:#ffffff">在佛教传入中国后，珠串项链与佛教教义相结合，在</span></span><strong>形制、珠子数量、颜色</strong><span style="color:#000000"><span style="background-color:#ffffff">上有了特定的规制。</span></span></span></span></span></p><p><span style="color:#000000"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">从<strong>珠子的形制上</strong>看，常见的可以分为以下四种：</span></span></span></span></span></p><p class="MsoNormal"></p><p><strong><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:14px">1、圆形珠链</span></span></span></strong></p><p style="text-align:justify;text-indent:2em;"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">圆形色均的翡翠珠串是价值最高的，因为珠链要成串相当不容易：首先每一颗质量都很接近、其次打磨珠子非常耗材、要选择完全无裂的、打孔时不能有任何偏差。</span></span></span></p><p style="text-align:justify;text-indent:2em;"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">只有满足这些条件，出来的珠串才有很高的价值。但是圆珠也是非常受欢迎的，它寓意佩戴者可以事事圆满，处世圆通，百事百顺。</span></span></span></p><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/10251715844693388_13360144499714302.jpg?sign=22a0556cc1346ffa2985b4896864e1ab&amp;t=1715844674"/></div><p></p><p class="MsoNormal"><strong><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">2、塔形珠</span></span></span></strong></p><p><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">这类珠串的特点是大小不一，以最大的珠子为中，向两头逐渐递减，有着财富越聚越多福气越聚越大的美好寓意。<span style="color:#000000"><span style="background-color:#ffffff">这种形状的珠链适合“圆脸”的顾客，可使脸部显长，增强面部的线条感。</span></span></span></span></span></p><p></p><p><strong><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">3、桶珠</span></span></span></strong></p><p class="MsoNormal"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">翡翠桶珠是翡翠珠宝中一种比较特殊的路路通形状，寓意四通八达、畅通无阻</span></span></span></p><p class="MsoNormal"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">佩戴在手上或脖子上时，可以来回转动，因此有着财源滚滚来之意。</span></span></span></p><p class="MsoNormal"></p><p class="MsoNormal"><strong><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">4、小米珠</span></span></span></strong></p><p class="MsoNormal"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">是近年来翡翠圈的新晋宠儿，直径通常在1-4mm，相较于传统翡翠饰品，翡翠小米珠款式百搭且佩戴方式多样，可单独佩戴，可叠戴，亦可与其他饰品进行混搭，深受消费者们的喜爱，同时也有着吉祥如意、幸福美满之意。</span></span></span></p><p class="MsoNormal"> </p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/15261715844876909_3.png?sign=8df06b3df131a0b75b34388f89016a25&amp;t=1715844858"/></div><p></p><p class="MsoNormal"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">从<strong>数量上</strong>来看，不同的数量代表不同寓意</span></span></span></p><p class="MsoNormal"></p><p class="MsoNormal"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>108颗</strong>：108颗佛珠是最为常见的数目，佩戴108颗珠子的手串可消除烦恼，收获平安如意。</span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>54颗</strong>：代表佛教修行者一步步修成正果的54个步骤，寓意佩戴者通过自身努力，能力有突飞猛进的提高。诸事顺利、事事大吉。</span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>52颗</strong>：52颗是源自菩萨修行单的52个阶位，可以当做护身符，只要心存善念，就能得到菩萨的底佑。</span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>48颗</strong>：寓意人生四平八稳、步步高升，稳中有胜。</span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>36颗</strong>：可以理解为是108颗的低配版本。通常也认为是为了便于携带，遂三分一百零八颗成三十六颗。</span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>27颗</strong>：表示27位小乘佛教得道的圣贤。象征三才长久，天长久、地长久、人长久。</span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>21颗</strong>：表示十地，十波罗蜜、佛果二十一个位次，“佛果”指达到zui究竟成佛的果位。</span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>18颗</strong>：代表可以得到十八罗汉的底佑,又称十八子，寓意多子多福，18谐音要发，又寓意一路发财。</span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>14颗</strong>：寓意观音菩萨给六道众生14种无谓的功德，护佑众生平安。</span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>13颗</strong>：在佛教中的吉祥数字，代表功德圆满。</span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>12颗</strong>：代表一年十二月舒心。</span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>10颗</strong>：寓意十全十美，佩戴的人能得到事事如意的祝福。</span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>8颗</strong>：8的谐音是“发”，在中国一直是好兆头的吉利数字，也代表“仁、义、智、勇、洁礼、忠、信”等8种品格。</span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>1颗</strong>：单珠的珠子，寓意转运珠代表了峰回路转，时来运转，带来很多好运气。</span></span></span></p><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/12721715844932792_72粒.jpg?sign=3a658fa1b4e599a08122630d151ee62c&amp;t=1715844914"/></div><p></p><p><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">从<strong>颜色搭配上</strong>来看，<span style="color:#000000"><span style="background-color:#ffffff">不同的翡翠颜色搭配也有不同的寓意。</span></span></span></span></span></p><p><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>1.黄色+绿色</strong><span style="background-color:#ffffff">：又称“皇家绿”，黄翡绿翠，非常具有观赏性、给人留下很深的视觉冲击。强烈的对比色让人感受皇家般的气度和风范。</span></span></span></span></span></p><p><span style="background-color:#ffffff"><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>2.紫色+绿色</strong>：称为的“春带彩”，寓意春风得意，博得众人喝彩。</span></span></span></span></span></p><p><span style="background-color:#ffffff"><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>3.红色+绿色+紫色</strong>：称为“福禄寿三彩翡翠”，寓意福气、高官、长寿，包含了人生最美好的三种运气。</span></span></span></span></span></p><p><span style="background-color:#ffffff"><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>4.红色+绿色+紫色+白色（或黄色）</strong>：“福禄寿喜”，表示不仅高官厚禄，幸福长寿，还每天喜气洋洋，鸿运当头。</span></span></span></span></span></p><p><span style="background-color:#ffffff"><span style="color:#000000"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>5.红色+绿色+紫色+白色+黄色</strong>：“五福临门”，福禄寿喜财一应俱全，表现了人们对幸福生活的美好憧憬。</span></span></span></span></span></p><p></p><p style="text-align:left;" size="0" _root="undefined" __ownerID="undefined" __hash="undefined" __altered="false"><span style="color:#000000"><span style="background-color:#ffffff"><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="font-size:16px"><strong>与手镯相比，翡翠珠串造型更加灵活多变，也不容易磕碰磨损，也是一种不错的选择。</strong></span></span></span></span></span></p>', 9, 1, 0, 35, NULL, NULL, NULL, NULL, NULL, NULL, 'IQ3eAXdGimWRcVU6', '2024-05-16 15:40:56', '2024-05-16 16:12:39', 0) ON DUPLICATE KEY UPDATE
