INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('jewelry', '戒面', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/19361715846296326_WechatIMG72.jpg', NULL, '<p class="MsoNormal"><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">翡翠戒面是指用于制作戒指的翡翠宝石部分，它通常由一块优质翡翠切割和打磨而成。翡翠戒面因其美丽的色泽、高透明度和坚硬的质地而备受推崇。佩戴翡翠戒指不仅象征着财富和地位，还被认为能带来好运和保护。</span></span></span></span></span></p><p class="MsoNormal"> </p><p class="MsoNormal"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong><span style="color:#333333"><span style="background-color:#ffffff">圆形/椭圆形戒面</span></span></strong></span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="color:#333333"><span style="background-color:#ffffff">圆形/椭圆形形状的翡翠戒面是经常能看到的，可以说在戒指款式是基础款，男士和女士都很适合。但结缘椭圆形戒面的时候需要看比例是否协调，过长过短可能会没有这么好看</span></span></span></span></span></p><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/12041715846839747_圆形.jpg?sign=e7a31ef0da8d4f5867c7dbe1fd1af487&amp;t=1715846821"/></div><p><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>方形<span style="color:#333333"><span style="background-color:#ffffff">戒面</span></span></strong></span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="color:#333333"><span style="background-color:#ffffff">相对于圆形和椭圆形翡翠戒面，方形的翡翠见面对男士更友好。正方形的翡翠戒面大气上档次，有一种庄重的风格，可以充分提现出男士的气质</span></span></span></span></span><br/></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/16811715846865717_长方形1.jpg?sign=a56833ae0c293027149035501fb6ff1f&amp;t=1715846846"/></div><p><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="color:#333333"><span style="background-color:#ffffff"><strong>马眼形戒面</strong></span></span></span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="color:#333333"><span style="background-color:#ffffff">马眼形翡翠戒面形似马眼，中间鼓，两头尖，也被叫做橄榄形。马眼形戒面线条优美，特别适合修饰指形</span></span></span></span></span><br/></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/11771715846879934_马眼形.jpg?sign=d43bcea58fe0756924de3f187c4ed504&amp;t=1715846861"/></div><p><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong><span style="color:#333333"><span style="background-color:#ffffff">马鞍形戒面</span></span></strong></span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="color:#333333"><span style="background-color:#ffffff">马鞍形整体上呈现为长条形，形似古代的骑具马鞍，因而天然带着一种阳刚大气的绅士感，马鞍形翡翠戒面合适男士佩戴</span></span></span></span></span><br/></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/10141715846890811_马鞍形.JPG?sign=33bc280df67fa7b0f46677fea928498f&amp;t=1715846872"/></div><p><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong><span style="color:#333333"><span style="background-color:#ffffff">随形戒面（不规则戒面）</span></span></strong></span></span></span><br/><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><span style="color:#333333"><span style="background-color:#ffffff">随形就是比较随意的一种形状，可以是雕刻的，可以是因为原石的形状，没有经过太多的处理的，这种随形的翡翠戒面，一般来说，都是根据料子的原来的形状来确定的。</span></span></span></span></span></p><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/18221715846906503_随形.jpg?sign=81f498247b33572cbe5eef8c05cf5bde&amp;t=1715846887"/></div><p></p>', 7, 1, 0, 26, NULL, NULL, NULL, NULL, NULL, NULL, 'm5uJui7zi6aHvusr', '2024-05-16 16:08:21', '2024-05-16 16:13:41', 0) ON DUPLICATE KEY UPDATE
