INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('jewelry', '摆件', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/13221715845750009_WechatIMG73.jpg', NULL, '<p class="MsoNormal"><span style="color:#191919"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">“翡翠摆件”是一种可以摆放在公共区域、桌、柜或者橱里供人欣赏的收藏品，主要用于摆设、收藏和赏玩，通常有着较高的艺术性和较强的观赏性；</span></span></span></span></span></p><p><span style="color:#191919"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">中国翡翠行业的“四大国宝”，就都是翡翠摆件。台北“故宫博物院”的三大镇馆之宝，就有慈禧太后收藏过的“翡翠白菜”。</span></span></span></span></span></p><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/14811715845926229_岱岳奇观.png?sign=fb0efac3137a94dfb1f453d0b0478043&amp;t=1715845907"/></div><p style="text-align:center;"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">《岱岳奇观》</span></span></span></p><p class="MsoNormal"> </p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/16091715845940520_含香聚瑞.png?sign=d546b419d479009c58cb2baeee7399a5&amp;t=1715845921"/></div><p style="text-align:center;"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">《含香聚瑞》</span></span></span></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/13231715845948854_群芳揽胜.png?sign=2f85242a9731e4b97361570256eead0d&amp;t=1715845930"/></div><p style="text-align:center;"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">《群芳揽胜》</span></span></span></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/16571715845958753_四海腾欢.png?sign=f9ce985b4da312dbe2a14b831e854e39&amp;t=1715845939"/></div><p style="text-align:center;" size="0" _root="undefined" __ownerid="undefined" __hash="undefined" __altered="false"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">《四海腾欢》</span></span></span></p><p class="MsoNormal"></p><p><span style="color:#191919"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">摆件的价值主要体现在原料价值和工艺价值上，其雕刻所耗费的工时很多，有些大型摆件的雕刻，需要由多名玉雕师共同完成，耗费几个月甚至两三年的时间。翡翠摆件的题材种类与风格很多，每个题材背后都有着美好的寓意。</span></span></span></span></span></p><p class="MsoNormal"> </p><p class="MsoNormal"><span style="color:#191919"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>植物类</strong></span></span></span></span></span></p><p style="text-align:left;" size="1" _root="[object Object]" __ownerid="undefined" __hash="undefined" __altered="false"><span style="color:#191919"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">比较有代表意义的翡翠摆件是翡翠白菜。白菜与“摆财”读音相似，具有招拢财富、招财纳福的寓意。</span></span></span></span></span></p><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/14301715846126370_翡翠白菜.jpg?sign=eb5dc8a118b01c63bffaf130d95225dc&amp;t=1715846107"/></div><p> </p><p><span style="color:#191919"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>动物类</strong></span></span></span></span></span></p><p><span style="color:#191919"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">比较有代表意义的翡翠摆件是翡翠神龟。乌龟是长寿命的代表，因此翡翠神龟有身体健康、无病无灾的含义,翡翠神龟还寓意着升官发财、财源滚滚。</span></span></span></span></span></p><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/14501715846182399_1.png?sign=72b537ec2e582ae5dfcf916c117da2de&amp;t=1715846163"/></div><p></p><p><span style="color:#191919"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px"><strong>神话主题类</strong></span></span></span></span></span></p><p><span style="color:#191919"><span style="background-color:#ffffff"><span style="font-size:14px"><span style="line-height:1.75"><span style="letter-spacing:2px">这类的翡翠摆件更多，什么翡翠观音、翡翠佛、翡翠貔貅等等。翡翠观音和翡翠佛的含义都是保佑家人身体健康、万事如意、无病无灾，而翡翠貔貅则是寓意着财源滚滚、大富大贵。</span></span></span></span></span></p><p></p><div class="media-wrap image-wrap"><img class="media-wrap image-wrap" src="https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-16/10391715846193444_2.png?sign=f0924abd5e1bd5baaeffe5bb83872144&amp;t=1715846174"/></div><p></p>', 5, 1, 0, 26, NULL, NULL, NULL, NULL, NULL, NULL, 'E7SMhhwNp2roZxQA', '2024-05-16 15:56:17', '2024-05-16 16:14:05', 0) ON DUPLICATE KEY UPDATE
