INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '景颇绿叶宴', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/18321715767352779_绿叶宴2.jpg', '原汁原味、地地道道的“绿色食品', '<p><span style="letter-spacing:1px"><span style="line-height:1.75"><strong><span style="font-size:20px">绿叶宴</span></strong></span></span></p><p><span style="font-size:16px"><span style="letter-spacing:1px"><span style="line-height:1.75"><strong>原汁原味、地地道道的“绿色食品”</strong></span></span></span></p><p></p><p></p><p><span style="font-size:16px"><span style="letter-spacing:1px"><span style="line-height:1.75">景颇山寨中既古朴又带点野性的名宴。绿叶宴没有锅筷碗勺，一切饮食用具都是用翠竹和绿叶制成，吃的是山里采来的野菜、野果、野味，采用传统的烤、煮、炸、腌等手法烹制，用肥大的树叶或芭蕉叶包盛饭菜，用树叶叠成勺、盆盛汤，因满席翠绿、完全不用碗筷而得名，逐一打开“绿包”，有喷香的糯米饭，有鲜美的鱼腥草，有蜂蛹荷包蛋，还有飞蚂蚁煎饼、舂烤绿斑鸠、帕滚酸菜鱼等，称得上是原汁原味、地地道道的“绿色食品。</span></span></span></p>', 6, 1, 0, 29, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/14601715767363418_绿叶宴2.jpg"]', NULL, NULL, NULL, NULL, NULL, 'T8XInqPM1mAPYeW9', '2024-05-15 17:49:56', '2024-05-15 20:14:48', 0) ON DUPLICATE KEY UPDATE
