INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '撒撇', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/10671715767659435_撒撇.jpg', '德宏美食必吃小吃', '<p class="MsoNormal"><span style="line-height:1.75"><strong><span style="letter-spacing:1px"><span style="font-size:20px">撒撇</span></span></strong></span></p><p><span style="line-height:1.75"><strong><span style="font-size:16px"><span style="letter-spacing:1px">德宏美食必吃小吃</span></span></strong></span></p><p></p><p><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">主要由精瘦的牛肉、猪肉或鱼肉等动物肉类捣烂成泥，配以韭菜、香柳、缅芫荽、小米辣等佐料，再加入由动物的“苦肠”熬制出的“苦水”或柠檬水调制成的调料，搭配烤熟的肉、野菜和凉米线一起食用的风味美食；在德宏，万物皆可撒，有苦撒、鱼撒、虾撒、柠檬撒、油辣子撒、羊奶果撒、茄子撒等多种类型，撒撇不仅是一种美食，还蕴含着丰富的文化意义，是傣族人民招待客人的上等食品。</span></span></span></p>', 5, 1, 0, 30, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/16471715767653510_撒撇.jpg"]', NULL, NULL, NULL, NULL, NULL, 'S6IUn3tOmgnw3X08', '2024-05-15 18:08:23', '2024-05-15 19:53:53', 0) ON DUPLICATE KEY UPDATE
