INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '火烧猪', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/15351715768235190_火烧猪.jpg', '“盈江三味”之一', '<p class="MsoNormal"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong><span style="font-size:20px">火烧猪</span></strong></span></span></p><p><span style="color:#333333"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="letter-spacing:1px"><strong>“盈江三味”之一</strong></span></span></span></span></p><p></p><p><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">德宏独特的火烧技法制作的烤乳猪，搭配腌菜膏、鱼腥菜、芫荽、小米辣等制作的蘸水。火烧猪的烹饪技法独特，肉质鲜嫩多汁，搭配蘸水食用，味道鲜美，香气扑鼻。这道美食体现了德宏人对食材原汁原味的追求和独特的烹饪技艺。</span></span></span></p>', 4, 1, 0, 3, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/16881715768244090_火烧猪.jpg"]', NULL, NULL, NULL, NULL, NULL, 'dn53OkL4tMGS365z', '2024-05-15 18:18:31', '2024-05-15 19:55:03', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
  sort=VALUES(sort), status=VALUES(status), isRecommend=VALUES(isRecommend), readCount=VALUES(readCount),
