INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '过手米线', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/10881715768348223_过手米线.jpg', '非物质文化遗产代表', '<p class="MsoNormal"><span style="line-height:1.75"><strong><span style="font-size:20px"><span style="letter-spacing:1px">过手米线</span></span></strong></span></p><p><span style="line-height:1.75"><strong><span style="font-size:16px"><span style="letter-spacing:1px">非物质文化遗产代表美食</span></span></strong></span></p><p></p><p><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">德宏州阿昌族特有的小吃，吃时因需先取一团<span style="color:#000000"><a href="https://baike.baidu.com/item/%E7%B1%B3%E7%BA%BF/0?fromModule=lemma_inlink">米线</a></span>置于手心，然后将拌料放在米线上食用，由此而得名&quot;过手米线&quot;，过手米线口感软糯无渣，酸辣鲜香，是一种非常特别的手抓食品；而在2018年，阿昌族过手米线制作技艺入选第四批德宏州州级非物质文化遗产代表性项目名录。</span></span></span></p>', 3, 1, 0, 1, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/12301715768354356_过手米线.jpg"]', NULL, NULL, NULL, NULL, NULL, 'aU0TIVDvHWvLNBN3', '2024-05-15 18:20:23', '2024-05-15 19:55:53', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
  sort=VALUES(sort), status=VALUES(status), isRecommend=VALUES(isRecommend), readCount=VALUES(readCount),
