INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '泡鲁达', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/10671715768755050_泡鲁达.jpeg', '风靡东南亚的饮品', '<p class="MsoNormal"><span style="line-height:1.75"><strong><span style="letter-spacing:1px"><span style="font-size:20px">泡鲁达</span></span></strong></span></p><p><span style="line-height:1.75"><strong><span style="letter-spacing:1px"><span style="font-size:16px">风靡东南亚的饮品</span></span></strong></span></p><p></p><p><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:16px">最初源自东南亚国家，泡鲁达起先是在缅甸、泰国等东南亚国家流行，后来逐渐流行到德宏瑞丽。泡鲁达用西米、大西米、紫米、木瓜冻、炼乳、特制奶油面包干、新鲜椰丝加上碎冰块做成，香甜扑鼻，神清气爽，奶油面包干，泡在奶香浓郁的冰水中，入口即软，酥脆香甜，可口甜蜜。它是傣族风味的冷饮甜食，是德宏州最有名的小吃之一。</span></span></span></p>', 2, 1, 0, 6, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/16651715768761566_泡鲁达.jpeg"]', NULL, NULL, NULL, NULL, NULL, 'hA6aPYKc8ouowhQy', '2024-05-15 18:26:31', '2024-05-15 19:56:25', 0) ON DUPLICATE KEY UPDATE
