INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '泼水粑粑', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/15401715768905044_泼水粑粑.jpeg', '泼水节限定美食', '<p style="text-align:left;" class="MsoNormal"><span style="color:#222222"><span style="background-color:#ffffff"><span style="line-height:1.75"><strong><span style="letter-spacing:1px"><span style="font-size:20px">泼水粑粑</span></span></strong></span></span></span></p><p><span style="color:#222222"><span style="background-color:#ffffff"><span style="line-height:1.75"><strong><span style="font-size:16px"><span style="letter-spacing:1px">泼水节限定美食</span></span></strong></span></span></span></p><p></p><p><span style="color:#222222"><span style="background-color:#ffffff"><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">德宏州德昂族风味小吃，是在泼水节时必不可少的美食。泼水粑粑的主要原料是糯米和芭蕉叶，将糯米磨成吊浆粉，加入红塘揉合成粉团状，放在新鲜的芭蕉叶上，适当压成扁长状，蒸熟后即可食用。口感糯软香甜，外包裹的芭蕉叶还带有一股清香味道，口感非常特别。</span></span></span></span></span></p>', 1, 1, 0, 0, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/19131715768918048_泼水粑粑.jpeg"]', NULL, NULL, NULL, NULL, NULL, 'P98gBVE0hmSzlGTv', '2024-05-15 18:28:44', '2024-05-15 19:56:54', 0) ON DUPLICATE KEY UPDATE
