INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '景颇鬼鸡', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/15941715767148953_景颇鬼鸡.jpg', '名字听着吓人
味道尝起来惊人', '<p style="text-align:left;" size="5" _root="[object Object]" __ownerID="undefined" __hash="undefined" __altered="false"><span style="color:#222222"><span style="background-color:#ffffff"><span style="line-height:1.75"><strong><span style="letter-spacing:1px"><span style="font-size:20px">鬼鸡</span></span></strong></span></span></span></p><p><span style="color:#222222"><span style="background-color:#ffffff"><span style="line-height:1.75"><strong><span style="font-size:16px"><span style="letter-spacing:1px">名字听着吓人味道尝起来惊人</span></span></strong></span></span></span></p><p></p><p><span style="color:#222222"><span style="background-color:#ffffff"><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">鬼鸡起源于云南景颇族的一种祭祀仪式。祭祀结束后，当地人就会直接在野外，把献祭过的鸡肉撕成小块，加入当地随处可见的各种香草和调料，拌匀后吃掉，因此得名，而且鬼鸡制作技艺源远流长，已有数百年的历史。鬼鸡口感鲜嫩，酸辣适中，酸中带微甜，清新开胃。柠檬和香菜的清新融入鸡肉中，酸香开胃，加上新鲜辣椒释放出的鲜辣，让人一口接一口。</span></span></span></span></span></p>', 0, 1, 0, 52, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/16901715767154745_景颇鬼鸡.jpg"]', NULL, NULL, NULL, NULL, NULL, 'Ij7sZ8HtrdyKovVC', '2024-04-24 16:11:29', '2024-05-15 19:57:31', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
  sort=VALUES(sort), status=VALUES(status), isRecommend=VALUES(isRecommend), readCount=VALUES(readCount),
  album=VALUES(album), address=VALUES(address), coordinate=VALUES(coordinate), mobile=VALUES(mobile),
