INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '景颇舂菜', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/19511715767486911_舂菜.jpeg', '舂筒不响，吃饭不香', '<p style="text-align:left;" class="MsoNormal"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong><span style="font-size:20px">景颇舂菜</span></strong></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong>“舂筒不响，吃饭不香“</strong></span></span></span></p><p></p><p><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">景颇族有“舂筒不响，吃饭不香”的说法。用竹筒和木棒舂制烤熟的肉类、竹笋、苦子果等果蔬，辣中带香、香中微苦、苦中回甜的滋味很是独特。舂菜原料一年四季不缺，分舂荤菜(主要是肉类)与舂素菜(有各种果蔬，不需经过煮熟)。舂菜中的野菜多是凉菜，夏天吃起来格外爽口，<span style="color:#222222"><span style="background-color:#ffffff">舂菜的独特之处在于其独特的舂制工艺和丰富的食材搭配，味道鲜美，口感独特。</span></span></span></span></span></p>', 0, 1, 0, 6, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/17211715767491418_舂菜.jpeg"]', NULL, NULL, NULL, NULL, NULL, 'ikepfydnroxdrT2Y', '2024-05-15 18:04:41', '2024-05-15 19:58:38', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
  sort=VALUES(sort), status=VALUES(status), isRecommend=VALUES(isRecommend), readCount=VALUES(readCount),
  album=VALUES(album), address=VALUES(address), coordinate=VALUES(coordinate), mobile=VALUES(mobile),
