INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '景颇竹筒菜', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/17081715767542991_景颇-竹筒菜.jpg', '以竹筒为炊，以鲜食为品', '<p><span style="line-height:1.75"><span style="letter-spacing:1px"><strong><span style="font-size:20px">景颇竹筒菜</span></strong></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong>以竹筒为炊，以鲜食为品</strong></span></span></span></p><p></p><p><span style="color:#222222"><span style="background-color:#ffffff"><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">竹筒是景颇人重要的天然厨具，不仅用来做饭，还用来做菜，将处理好的牛肉、鱼、田鸡等食材塞入竹筒中，压实捆紧后置阴干处保存，或直接烹饪烤熟。竹筒菜口感细嫩上牙，清香醇美，营养丰富，开胃健脾。特有的鲜竹和酵菜合成的独特风味。</span></span></span></span></span></p>', 0, 1, 0, 7, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/10211715767547001_景颇-竹筒菜.jpg"]', NULL, NULL, NULL, NULL, NULL, 'bCJmOAA3FsZd3w8V', '2024-05-15 18:05:51', '2024-05-15 20:00:03', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
  sort=VALUES(sort), status=VALUES(status), isRecommend=VALUES(isRecommend), readCount=VALUES(readCount),
