INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '酸扒菜', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/17361715767741329_酸扒菜.jpg', '傣族人均都爱吃的美食', '<p style="text-align:left;" class="MsoNormal"><span style="color:#222222"><span style="background-color:#ffffff"><span style="line-height:1.75"><strong><span style="letter-spacing:1px"><span style="font-size:20px">酸扒菜</span></span></strong></span></span></span></p><p><span style="color:#222222"><span style="background-color:#ffffff"><span style="line-height:1.75"><strong><span style="font-size:16px"><span style="letter-spacing:1px">傣族人均都爱吃的美食</span></span></strong></span></span></span></p><p></p><p><span style="color:#222222"><span style="background-color:#ffffff"><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">傣语称“帕格左”，在傣族地区，它无人不知，无人不晓，无人不爱，傣族日常生活、过节、办宴席都少不了它，它主要由蔬菜、肉类和调料制成，吃时再放上一些生的小米辣、缅芫荽，吃起来酸到位、辣到位、香到位，酸香酸香的特别开胃。</span></span></span></span></span></p>', 0, 1, 0, 0, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/18651715767747682_酸扒菜.jpg"]', NULL, NULL, NULL, NULL, NULL, 'hHqeitGjGCsNjqfI', '2024-05-15 18:09:34', '2024-05-15 20:01:31', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
  sort=VALUES(sort), status=VALUES(status), isRecommend=VALUES(isRecommend), readCount=VALUES(readCount),
  album=VALUES(album), address=VALUES(address), coordinate=VALUES(coordinate), mobile=VALUES(mobile),
