INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '酸笋煮鸡', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/11001715767820001_酸笋煮鸡.jpeg', '傣族美女的秘密武器', '<p><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">酸笋煮鸡</span></span></span></strong></p><p><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">傣族美女的秘密武器</span></span></span></strong></p><p></p><p><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">傣族人家随便哪家都有百来斤酸笋，一天也离不开，对于第一次吃笋的人来说，大多数都难于接受它的怪味，但一旦吃过了就会被它臭中带香的奇异口感所折服；酸笋煮鸡将腌制的酸笋、西红柿与鸡肉放入锅里同煮，待鸡肉煮烂后起锅，即可食用。再配上一碗用大蒜、小米辣、缅芫荽制作的“蘸水”，其味酸辣爽口，酸笋傣家还用来煮肉、煮鱼，制法与酸笋煮鸡相同。</span></span></span></p>', 0, 1, 0, 1, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/17671715767827477_酸笋煮鸡.jpeg"]', NULL, NULL, NULL, NULL, NULL, 'zCdR0PlALk1f1TLX', '2024-05-15 18:10:53', '2024-05-15 20:02:33', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
  sort=VALUES(sort), status=VALUES(status), isRecommend=VALUES(isRecommend), readCount=VALUES(readCount),
