INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '香茅草烤鱼', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/12551715767884748_香茅草烤鱼.jpg', '鱼和草的最佳cp', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">香茅草烤鱼</span></span></span></strong></p><p><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">鱼和草的最佳cp</span></span></span></strong></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">自带柠檬清香的香茅草，配上葱姜蒜，填进鲜甜细嫩的罗非鱼肚子里，绑在一起放在火上烤，腌制的香料与鱼肉的香味完美融合，堪称鱼和草的最佳CP，酸甜的柠檬香和焦嫩的鱼香混合，使得这道菜充满了浓厚的傣族风情。</span></span></span></p>', 0, 1, 0, 1, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/14151715767890270_香茅草烤鱼.jpg"]', NULL, NULL, NULL, NULL, NULL, 'pcnzKN2r4qNi9kWN', '2024-05-15 18:11:59', '2024-05-15 20:03:06', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
  sort=VALUES(sort), status=VALUES(status), isRecommend=VALUES(isRecommend), readCount=VALUES(readCount),
