INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '帕哈煮螺蛳', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/14201715767986706_帕哈煮螺蛳.jpeg', '傣族百搭夜宵之一', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">帕哈煮螺蛳</span></span></span></strong></p><p><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">傣族百搭夜宵之一</span></span></span></strong></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">“帕哈”是傣语，意为臭菜，闻着臭，吃着香，是傣族人民饮食的一大特色；帕哈煮螺蛳，是傣族人民的美味佳肴，秋收时节，田螺壳薄肉厚，肉质嫩滑甘美，而且极易吮吸离壳，将两者辅以调料先炒后煮，以做法讲究、作料齐全，汤白味香及麻辣著称，嗦一碗螺蛳，配一瓶啤酒，就是傣族的百搭夜宵。</span></span></span></p>', 0, 1, 0, 0, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/13931715767992465_帕哈煮螺蛳.jpeg"]', NULL, NULL, NULL, NULL, NULL, 'CDghtmL6a6jpH5Gs', '2024-05-15 18:12:58', '2024-05-15 20:03:45', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
  sort=VALUES(sort), status=VALUES(status), isRecommend=VALUES(isRecommend), readCount=VALUES(readCount),
