INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '德宏泡鸡脚', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/17261715768077245_泡鸡脚.jpeg', '酸酸辣辣巨开胃', '<p class="MsoNormal"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong><span style="font-size:20px">德宏泡鸡脚</span></strong></span></span></p><p><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px"><strong>酸酸辣辣巨开胃</strong></span></span></span></p><p></p><p><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">吃过一次你就会爱上，精心挑选的鸡脚，经过处理后变得饱满而富有弹性，入口先是一阵酸辣的刺激，紧接着鸡脚的鲜嫩与嚼劲在口中散开，而且现在口味也有很多选择，蒜香、番茄、酱香、柠檬小米辣、涮涮辣……各种口味都有，无论是作为休闲的零食，还是餐桌上的美味点缀，德宏泡鸡脚都能让人欲罢不能。</span></span></span></p>', 0, 1, 0, 0, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/10941715768071962_泡鸡脚.jpeg"]', NULL, NULL, NULL, NULL, NULL, 'EpEsDq2IyqeVuPxr', '2024-05-15 18:14:35', '2024-05-15 20:04:33', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
  sort=VALUES(sort), status=VALUES(status), isRecommend=VALUES(isRecommend), readCount=VALUES(readCount),
  album=VALUES(album), address=VALUES(address), coordinate=VALUES(coordinate), mobile=VALUES(mobile),
