INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '火烧干巴', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/14731715768136976_火烧干巴.jpg', '牛肉喷香有嚼劲', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">火烧干巴</span></span></span></strong></p><p><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">牛肉喷香有嚼劲</span></span></span></strong></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">是采用肥膘黄牛，选其无筋、顺刀之精鲜肉，配以多种名贵且具清热降火之天然香料，经木炭火烧、木锤舂制而成，肉质细软，原汁原味，干而不燥，好吃不上火，是傣族最具特色的风味小吃。</span></span></span></p>', 0, 1, 0, 1, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/14541715768170350_火烧干巴.jpg"]', NULL, NULL, NULL, NULL, NULL, '3kdUv6CT9fs2NH9E', '2024-05-15 18:16:28', '2024-05-15 20:05:45', 0) ON DUPLICATE KEY UPDATE
