INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '德宏“海陆空”', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/16291715768462217_海陆空.jpg', '德宏之外再也吃不到', '<p><span style="line-height:1.75"><span style="letter-spacing:1px"><strong><span style="font-size:20px">德宏“海陆空”</span></strong></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong>德宏之外再也吃不到</strong></span></span></span></p><p></p><p><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">“靠山吃山靠江吃江”，阿昌族运用其智慧，适度、巧妙的结合自然，将美食呈现于餐桌上；“海”即水里游的，专指放养在无污染稻田中的稻花鱼，“陆”即地上长的，专指棕包米和鸡枞；“空”即天上飞的，专指成长饱满的黄蜂蜂蛹。这道菜把稻田鱼的“泥土味”、粽包的微苦后甜、蜂蛹的鲜香融为一体，醇香四溢，品尝过的客人无不叫“绝”。</span></span></span></p>', 0, 1, 0, 0, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/16361715768468275_海陆空.jpg"]', NULL, NULL, NULL, NULL, NULL, 'xMMRaBqUkviV9mtQ', '2024-05-15 18:22:17', '2024-05-15 20:06:30', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
  sort=VALUES(sort), status=VALUES(status), isRecommend=VALUES(isRecommend), readCount=VALUES(readCount),
