INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '黄花粑粑', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/10161715768576674_黄花粑粑.jpg', '德宏人自己的糯叽叽', '<p style="text-align:left;" size="1" _root="[object Object]" __ownerid="undefined" __hash="undefined" __altered="false"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong><span style="font-size:20px">黄花粑粑</span></strong></span></span></p><p><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px"><strong>德宏人自己的糯叽叽</strong></span></span></span></p><p></p><p><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">采摘新鲜的黄花，拌以糯米，炒香的苏子、红糖作为内陷，再沾上一层用染饭花染黄的糯米蒸制而成；黄花粑粑油润光亮，颜色金黄，染饭花的清香和红糖苏子独有的香味扑鼻而来，让人垂涎欲滴，吃起来也格外有味，粑粑入口软糯，馅料里的红糖遇热化汁，与苏子搭配出甜而不腻的流心口感，春的蓬勃与生机也仿佛融化在口中。</span></span></span></p>', 0, 1, 0, 5, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/14271715768584241_黄花粑粑.jpg"]', NULL, NULL, NULL, NULL, NULL, 'ZmPwLO5pFKe39Un8', '2024-05-15 18:23:52', '2024-05-15 20:07:11', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
  sort=VALUES(sort), status=VALUES(status), isRecommend=VALUES(isRecommend), readCount=VALUES(readCount),
