INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '甩粑粑', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/11631715768863970_甩粑粑.jpg', '东南亚“飞饼”', '<p style="text-align:left;" class="MsoNormal"><span style="color:#222222"><span style="background-color:#ffffff"><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">甩粑粑</span></span></span></strong></span></span></p><p><span style="color:#222222"><span style="background-color:#ffffff"><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">东南亚“飞饼”</span></span></span></strong></span></span></p><p></p><p><span style="color:#222222"><span style="background-color:#ffffff"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">源自于东南亚热带国家，在缅甸、泰国、印度等地非常流行，甩粑粑是德宏州的传统小吃之一，之所以叫甩粑粑，是因为制作此饼是要一定的技术含量的，制作时要把它甩起来，飞起来，经过煎炸后辅以炼乳，色泽金黄，质地松脆，味道香甜，嚼过之后，齿颊留芳。</span></span></span></span></span></p>', 0, 1, 0, 2, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/11061715768871533_甩粑粑.jpg"]', NULL, NULL, NULL, NULL, NULL, 'TOaAt6UEu99tUXow', '2024-05-15 18:27:37', '2024-05-15 20:12:03', 0) ON DUPLICATE KEY UPDATE
