INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '食用昆虫', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/18891715768958384_食用昆虫.jpeg', '勇敢者的美食', '<p class="MsoNormal"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong><span style="font-size:20px">食用昆虫</span></strong></span></span></p><p><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px"><strong>勇敢者的美食</strong></span></span></span></p><p></p><p><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">德宏各少数民族均有食用昆虫的习惯。食用昆虫具有蛋白质含量高、蛋白纤维少、营养成分易被人体吸收等特点，种类繁多，有蜂蛹、竹虫、蚂蚁卵、沙虫、蚂蚱、知了等，食用方法丰富多样，如：油煎蚂蚁卵、油炸蜂蛹、烧烤蚂蚱、爆炒蜂蛹、凉拌白蚂蚁卵等。</span></span></span></p>', 0, 1, 0, 32, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/15471715768962718_食用昆虫.jpeg"]', NULL, NULL, NULL, NULL, NULL, 'qFNhrMeRPq4xNkXp', '2024-05-15 18:29:35', '2024-05-16 10:14:22', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
  sort=VALUES(sort), status=VALUES(status), isRecommend=VALUES(isRecommend), readCount=VALUES(readCount),
  album=VALUES(album), address=VALUES(address), coordinate=VALUES(coordinate), mobile=VALUES(mobile),
