INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '瑞丽辣螃蟹', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/18861715769045925_炒螃蟹.jpg', '瑞丽必打卡美食', '<p class="MsoNormal"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong><span style="font-size:20px">瑞丽辣螃蟹</span></strong></span></span></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px"><strong>瑞丽必打卡美食</strong></span></span></span></p><p></p><p><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">瑞丽的螃蟹可是缅甸特有的一种淡水蟹，个头大，肉质肥美，味道和沿海的螃蟹不一样，为了保证缅甸口味原汁原味，很多螃蟹店从员工到厨师都是缅甸的；上一秒还是鲜活的螃蟹，下一秒就已经被炒制出锅，做好的辣螃蟹色泽诱人，香味扑鼻；不管什么季节，在瑞丽总能吃上带蟹黄的螃蟹。</span></span></span></p>', 0, 1, 0, 1, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/14161715769051580_炒螃蟹.jpg"]', NULL, NULL, NULL, NULL, NULL, 'zwpN8kjqh9WKgxwA', '2024-05-15 18:31:06', '2024-05-15 20:13:52', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
