INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('food', '德宏烧烤', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/13051715769137866_烧烤.jpeg', '德宏人民夜间的灵魂搭子', '<p style="text-align:left;" class="MsoNormal"><span style="color:#222222"><span style="background-color:#ffffff"><span style="line-height:1.75"><strong><span style="letter-spacing:1px"><span style="font-size:20px">德宏烧烤</span></span></strong></span></span></span></p><p><span style="color:#222222"><span style="background-color:#ffffff"><span style="line-height:1.75"><strong><span style="font-size:16px"><span style="letter-spacing:1px">德宏人民夜间的灵魂搭子</span></span></strong></span></span></span></p><p></p><p><span style="color:#222222"><span style="background-color:#ffffff"><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">德宏人夜间常吃的美食，包括烤肉串、烤韭菜、烤鱼等。德宏的烧烤以炭火烤制，食材新鲜，味道鲜美，再配合上各式特色蘸水腌菜膏蘸水、辣酱蘸水、百香果蘸水、洋番茄蘸水、干椒蘸水等，在夜晚的烧烤摊上，人们可以品尝到各种美味的烧烤，享受夜晚的美食盛宴。</span></span></span></span></span></p>', 0, 1, 0, 1, '["https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/10001715769127285_烧烤.jpeg"]', NULL, NULL, NULL, NULL, NULL, 'ofwvQFhFkecfkR9i', '2024-05-15 18:32:34', '2024-05-15 20:15:15', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
