INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '勐焕大金塔', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/18181715774813411_勐焕大金塔.jpeg', '中国南传上座部佛教第一塔', '<p class="MsoNormal"><span style="font-size:20px"><span style="line-height:1.75"><strong><span style="letter-spacing:1px">勐焕大金塔</span></strong></span></span></p><p class="MsoNormal"><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">中国南传上座部佛教第一塔</span></span></span></strong></p><p></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">勐焕大金塔坐落在德宏芒市城区东南方——孔雀湖畔的雷崖让山之巅，大金塔四周山清水秀，郁郁葱葱，环境幽雅。视野辽阔。高耸挺拔，雄伟壮观，气势恢宏。</span></span></span></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">勐焕大金塔属南亚傣王宮的建筑风格，有着深厚的民族文化/内涵，该塔是芒市地标性建筑，既是增进睦邻友好、中缅胞波情谊的桥染，更是吸引中外游客的一大佛教旅游胜地。</span></span></span></p>', 10, 1, 0, 49, NULL, '德宏州芒市东南部孔雀湖畔雷牙让山顶', '24.423257,98.596082', '(0692)2116199', '全年 08:30-18:30', '40', 'xYK8timfblAylAkd', '2024-05-15 20:08:47', '2024-05-23 11:46:06', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
  sort=VALUES(sort), status=VALUES(status), isRecommend=VALUES(isRecommend), readCount=VALUES(readCount),
  album=VALUES(album), address=VALUES(address), coordinate=VALUES(coordinate), mobile=VALUES(mobile),
  openTime=VALUES(openTime), ticketPrice=VALUES(ticketPrice), updateTime=VALUES(updateTime), isDelete=0;
INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '姐告口岸', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/16671715776355894_姐告口岸.jpeg', '国家级的边贸口岸', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="font-size:20px"><span style="letter-spacing:1px">姐告口岸</span></span></span></strong></p><p class="MsoNormal"><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">国家级的边贸口岸</span></span></span></strong></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">姐告，作为瑞丽市跨江唯一的村镇，陆路直接与缅甸相连，它也是320国道的终点，素有“天涯地角”之称。云南边贸进出口商品总额的50%均从此进入，作力国家级的边贸口岸，是中国对缅贸易陆路通道最繁忙的地区，国门对面是缅甸木姐市。国门分为三座宏伟建筑，依边境而建，中间为主国门，右边为货物通道，左边为人员通道。在主国门旁边有免税店，旅客可按规定购买进口商品。</span></span></span></p>', 9, 1, 0, 10, NULL, '德宏州瑞丽市姐告路姐告口岸', '23.977998,97.896899', NULL, '全天', '免费', 'XI64ifePkZjEvxl2', '2024-05-15 20:34:48', '2024-05-23 11:45:55', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
  sort=VALUES(sort), status=VALUES(status), isRecommend=VALUES(isRecommend), readCount=VALUES(readCount),
  album=VALUES(album), address=VALUES(address), coordinate=VALUES(coordinate), mobile=VALUES(mobile),
