INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '勐焕银塔', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/18681715775056271_银塔.jpg', '世界上最大的小乘佛教万佛塔', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="font-size:20px"><span style="letter-spacing:1px">勐焕大银塔</span></span></span></strong></p><p class="MsoNormal"><strong><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">世界上最大的小乘佛教万佛塔</span></span></span></strong></p><p></p><p class="MsoNormal"><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">勐焕大银塔坐落在德宏芒市的雷崖让山脚下，与勐焕大金塔遥相呼应。银塔通体洁白，熠熠生辉，宛如一颗璀璨的明珠镶嵌在山间。塔尖挂着风铃，微风一吹，在银玲声中追一场日落。</span></span></span></p><p class="MsoNormal"><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">勐焕大银塔融合了现代与传统的建筑风格，展现出独特的艺术魅力。它蕴含着深厚的民族文化底蕴，是芒市又一标志性建筑。这里不仅是人们感受佛教文化的圣地，也是游客们追寻心灵宁静的绝佳去处。</span></span></span></p>', 8, 1, 0, 8, NULL, '德宏傣族景颇族自治州芒市仙池路西200米', '24.41754,98.594817', '0692-3027968', '08:30-21:30开放', '40', '3MUOIIoAXjfxxPgm', '2024-05-15 20:13:53', '2024-05-23 11:45:43', 0) ON DUPLICATE KEY UPDATE
