INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '一寨两国', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/13771715776076818_一寨两国.jpeg', '一座秋千荡两国', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="font-size:20px"><span style="letter-spacing:1px">一寨两国</span></span></span></strong></p><p class="MsoNormal"><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">中国仅有一处的人文地理景观</span></span></span></strong></p><p></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">瑞丽“一寨两国”是国家AAAA级景区，位于德宏州瑞丽市银井村与缅甸芒秀村交界处。</span></span></span></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">中缅71号和72号界碑就在两个村寨之间，将原先一个傣族村寨一分为二，中方一侧的称为银井，缅方一侧的称为芒秀，形成了“一个傣族村寨分属中国和缅甸两个国家”的独特奇观。园区内有芒秀大金塔、中缅情人堤、一秋荡两国、一桥跨两国及一寨两国水井等景点；虽然是两个国家，但是村里的老百姓语言相通，习俗相同，他们同走一条路，共饮一井水，同赶一场集，和睦相处，世代传承，见证着友好的中缅友谊和源远流长的胞波情谊。</span></span></span></p>', 7, 1, 0, 7, NULL, '德宏州瑞丽市234省道（中缅边境71号界碑旁）', '23.95475,97.79604', '0692-4930777', '9:00-18:00', '39', 'bQFt2MWUav1tl4CM', '2024-05-15 20:30:13', '2024-05-23 11:45:30', 0) ON DUPLICATE KEY UPDATE
