INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '高山湖凯邦亚湖', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/14161715780490263_高山湖凯邦亚湖.png', '德宏州的“小千岛湖”', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="font-size:20px"><span style="letter-spacing:1px">高山湖凯邦亚湖</span></span></span></strong></p><p class="MsoNormal"><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">德宏州的“小千岛湖”</span></span></span></strong></p><p></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">凯邦亚，景颇族语意为收获的山谷。凯邦亚湖水面迁回曲折，近百个岛屿及无数半岛，看似岛岛相连，其实岛后有岛，岛水相间，仿佛蓬菜仙境。</span></span></span></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">凯邦亚湖景区规划面积22.8平方公里，水面8平方公里，平均海拔在1000米以上，年平均气温为14.2°，是回归自然、休闲度假的避暑胜地，景区分为自然景观游览区和自然游乐区两大部分，自然景观游览区主要由野生飞禽生态游览区、岛屿观光游览区、亚热带果园游览区、水源自然观光游览区组成。自然游乐区由水上游乐区、山林业区游乐区和野营活动区组成。</span></span></span></p>', 6, 1, 0, 10, NULL, '德宏州盈江县城西南40公里处', '24.566035,97.677104', '0692-2121340', '08:00-18:00', '免费', '32sp733AWtKqje7s', '2024-05-15 21:42:14', '2024-05-23 11:45:16', 0) ON DUPLICATE KEY UPDATE
