INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '盈江湿地公园', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-23/17611716433617570_WechatIMG11.jpg', '浓缩版的亚马逊', '<p><span style="line-height:2"><strong><span style="font-size:20px"><span style="letter-spacing:1px">盈江湿地公园</span></span></strong></span></p><p><span style="line-height:2"><strong><span style="font-size:16px"><span style="letter-spacing:1px">浓缩版的亚马逊</span></span></strong></span></p><p></p><p><span style="color:#333333"><span style="line-height:2"><span style="font-size:16px"><span style="letter-spacing:1px">大盈江为盈江县最大水系，纵贯盈江全境，将美丽的盈江坝一分为二，全长204.5公里，最宽处近1千米，最窄处仅7.5米。 1994年经国务院批准为国家级风景名胜区。</span></span></span></span></p><p><span style="color:#333333"><span style="line-height:2"><span style="font-size:16px"><span style="letter-spacing:1px">云南盈江国家湿地公园位于德宏州盈江县西南部平原镇、太平镇和弄璋镇境内大盈江流域内，北至大盈江上游弄璋镇飞勐村邦巴老寨村民小组，南至大盈江下游太平镇拉丙村轩岗村民小组，东西以河堤外侧为界。按江域中心线长度计全长24.8公里，总规划面积1725.98公顷，其中湿地面积为1365.10公顷，湿地率为79.09%。湿地公园现有记录的脊椎动物共 228 种，受国家保护的动物共 145 种。湿地公园范围内共有维管束植物143 科438 属663 种，滇桐、千果榄仁、红椿、茉莉果、马槟榔等 5 种为国家 II 级保护植物，是浓缩版的亚马逊。</span></span></span></span></p><p><span style="color:#333333"><span style="line-height:2"><span style="font-size:16px"><span style="letter-spacing:1px">2018年底被国家草原局赋予国家湿地公园、2019年10月被聘为AAA级景区。</span></span></span></span></p>', 2, 1, 0, 9, NULL, '德宏傣族景颇族自治州盈江县政府对面', '24.685919,97.93981', '0692-8127118,18587032177', '8:30-19:00,18:00停止入场', '30元', 'heNDBdH4qnYsZXMY', '2024-05-23 11:09:17', '2024-05-23 11:49:07', 0) ON DUPLICATE KEY UPDATE
