INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '勐戛仙佛洞', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-23/15961716434838535_3d702ae0c5f04da8876bfdbc4062f70a.jpeg', '1.4亿年光阴沉淀的别有洞天', '<p><span style="line-height:2"><strong><span style="letter-spacing:1px"><span style="font-size:20px">勐戛仙佛洞</span></span></strong></span></p><p><span style="line-height:2"><strong><span style="letter-spacing:1px">1.4亿年光阴沉淀的别有洞天</span></strong></span></p><p></p><p><span style="color:#333333"><span style="line-height:2"><span style="letter-spacing:1px"><span style="background-color:#ffffff">仙佛洞是一处已有1.4亿多年历史的</span><a href="https://www.meet99.com/jingdian-mangshixianfodong-143475.html">溶洞</a><span style="background-color:#ffffff">景观，</span>位于云南省德宏傣族景颇族自治州芒市城西南勐戛镇风吹坡，是滇西第一喀斯特熔岩洞，洞内包括了莲花谷、千层肚、乾坤仗、许愿池、翡翠瑶池、生命之源、时空隧道、锁情桥、太阳门、天籁之音等小景点；<span style="background-color:#ffffff">灯光配合声、光、电技术，使</span><a href="https://www.meet99.com/jingdian-mangshixianfodong-143475.html">溶洞</a><span style="background-color:#ffffff">显得更加绚丽多彩，仙雾缭绕，若隐若现。</span></span></span></span></p><p><span style="background-color:#ffffff"><span style="color:#333333"><span style="line-height:2"><span style="letter-spacing:1px">每年春天，仙佛洞的上万株“羊蹄甲”也将迎来盛花期，“羊蹄甲”叶如羊蹄，花如仙子，粉色和白色的花朵一簇挨着一簇，繁花似锦，美不胜收。</span></span></span></span></p>', 1, 1, 0, 4, NULL, '云南省德宏傣族景颇族自治州芒市勐戛镇风吹坡（仙佛洞景区）', '24.329809,98.51401', '0692-3068555;13578221916', '09:00-17:00(全天)；停止入场时间:17:00 ', '68元', 'NxGQlfb8UjFCSooK', '2024-05-23 11:32:28', '2024-05-23 11:49:30', 0) ON DUPLICATE KEY UPDATE
