INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '勐巴纳西珍奇园', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/14441715775557871_勐巴纳西奇珍园.jpg', '稀、奇、古、怪的园林', '<p class="MsoNormal"><strong><span style="font-size:20px"><span style="line-height:1.75"><span style="letter-spacing:1px">勐巴纳西珍奇园</span></span></span></strong></p><p class="MsoNormal"><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">稀、奇、古、怪的园林</span></span></span></strong></p><p></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">拥有四项全国之最——古树名木数量之多，年代之古为全国之最：奇石、树化石，龙其是世界上罕见的树化玉，规格之大、精品之多为全国之最：大型根雕造型之美、形状之奇、品位之高为全国之最；大树移植数量之多，成活率之高，为全国之最。园内春有花、夏有苗、秋有果、冬有绿，恍如一个美妙神奇的世界，令人叹为观止。</span></span></span></p>', 0, 1, 0, 6, NULL, '云南省德宏傣族景颇族自治州芒市勇罕街29号', '24.42616,98.58804', '0692-2104266', '08:00-18:00', '30元', '9nOQOcx3NJQKA7mT', '2024-05-15 20:19:27', '2024-05-23 11:51:26', 0) ON DUPLICATE KEY UPDATE
  type=VALUES(type), name=VALUES(name), cover=VALUES(cover), intro=VALUES(intro), content=VALUES(content),
