INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '树包塔', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/13261715775642939_树包塔.jpeg', '塔树浑然一体的绝景', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">树包塔</span></span></span></strong></p><p class="MsoNormal"><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">塔树浑然一体的绝景</span></span></span></strong></p><p></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">据傣文史料记载，清乾隆五十三年，即公元1778年，芒市第十七世土司放愈著为纪念一场胜利的战争而修处了此塔，距今两百多年。</span></span></span></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">此塔系砖石砌成，高约十余米，呈八角形、神龛内放着佛像。砖砌的塔身天长日久出现了裂缝，风中渐渐积满了尘土，一粒榕树种子被风或鸟带到了塔缝中，春雨浇下，种子生根发芽，于是古塔就渐渐被榕树包了起来，形成树包塔奇观。如今顶上的树已高达30余米，树冠覆盖近1000平方米。</span></span></span></p>', 0, 1, 0, 3, NULL, '云南省德宏傣族景颇族自治州芒市勇罕街与胞波路交叉口西100米', '24.435287,98.584308', NULL, '08:00-18:00（全天）', '免费', 'PmYTWmWyP3og3Cqw', '2024-05-15 20:21:57', '2024-05-23 11:52:21', 0) ON DUPLICATE KEY UPDATE
