INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '芒市新玩厂', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/14571715775863354_新玩厂.jpg', '从机械厂到网红顶流', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">芒市新玩厂</span></span></span></strong></p><p class="MsoNormal"><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">从机械厂到网红顶流</span></span></span></strong></p><p></p><p style="text-align:left;" class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">芒市新玩厂的原身是芒市机械厂，是唯一一个工业改造园区，是在原有机械厂厂房基础上改造而成，既保留住了老厂房60年的风华，也带入了充满新意的商业文化，涂鸦街打卡拍照，夜市小吃街大快朵颐，还有游戏厅，台球厅，电影院，livehouse等，从白天玩到晚上，从机械厂变成了新玩厂，逐渐成为芒市地区的“夜游宝藏地”</span></span></span></p>', 0, 1, 0, 6, NULL, '德宏傣族景颇族自治州芒市勐焕街道河东路', '24.443491,98.600958', NULL, '08:22:00（全天）', '免费', 'bGUfutIodyLh5UAM', '2024-05-15 20:26:00', '2024-05-23 14:00:25', 0) ON DUPLICATE KEY UPDATE
