INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '黑河老坡', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/12241715776006841_黑河老坡.jpeg', '柔软的高山草甸', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">黑河老坡</span></span></span></strong></p><p class="MsoNormal"><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">柔软的高山草甸</span></span></span></strong></p><p class="MsoNormal"></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">在黑河老坡自然保护区内，不仅有一望无际的高山草甸自然景观，也有晴雨不定的亚热带原始森林，丛林之中时时弥漫着雾气，仿似梦中仙境一般。黑河老坡雨量充沛，保护区内形成有明显的垂直带谱，植物物种丰富。高等植物达2500多种，省级珍稀濒危保护植物18种。动物约69种，有国家一、二级珍稀野生动物蜂猴、熊、白鹇等23种，在2836米的高山原始森林里融入自然、感悟自然。</span></span></span></p>', 0, 1, 0, 3, NULL, '德宏州芒市110乡道南50米', '24.222228,98.591405', '0692-3029169', '8:30-17:30', '40', 'aSQyjBj2lJcZ1g6i', '2024-05-15 20:27:34', '2024-05-23 11:54:54', 0) ON DUPLICATE KEY UPDATE
