INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '独树成林', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/16941715776683492_独树成林.jpg', '云南边陲热带自然奇观', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">独树成林</span></span></span></strong></p><p><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:16px">云南边陲热带自然奇观</span></span></span></strong></p><p></p><p><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">在瑞丽市姐勒乡芒令寨旁，远远就可看到一片伟岸青翠的榕树林列队路旁，就像在迎候远方的客人。其实这片榕树仅是一棵大榕树，因母株干向四周发展，又从枝干生出气根，气根入土又长成粗干，再向更远的地方发展，组成了这一片榕树林，成为令人叹为观止的独树成林奇景。据考证，这棵大榕树树龄已超过百年，主干要七八个人才能合抱，枝緊叶茂，四季常青，气极你泸，覆盖面宽达4亩多，成为瑞丽亚热带风光代表性的一景。</span></span></span></p>', 0, 1, 0, 1, NULL, '南省德宏傣族景颇族自治州瑞丽市边境贸易区内的曼掌寨子旁(民族风情园内)', '24.052414,97.959704', '0692-4100239', '08:00-19:00', '15元', 'FfxWKN25gjyabG8s', '2024-05-15 20:38:12', '2024-05-23 11:56:32', 0) ON DUPLICATE KEY UPDATE
