INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '莫里瀑布', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/14921715777604458_莫里森林公园.jpg', '天然森林氧吧', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">莫里瀑布</span></span></span></strong></p><p><span style="font-size:16px"><span style="letter-spacing:1px"><strong><span style="line-height:1.75">天然</span></strong><span style="color:#000000"><span style="background-color:#ffffff">森林</span></span><strong><span style="line-height:1.75">氧吧</span></strong></span></span></p><p class="MsoNormal"></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">莫里热带雨林，被称为“中国西南的翡翠谷”。莫里热带雨林景区的森林覆盖率达96%以上，生长着1540种植物种类和479种花卉及香料，除放养动物外，景区内有野猪、狗熊、麋鹿、蟒蛇、孔雀、青猴等野生珍禽异兽。在不见天日的雨林中穿行许久，隐约听到跌水声，循声前行至峡谷尽头，声音大如雷鸣，眼界忽然开阔，这就是闻名遐迩的莫里瀑布。只见清澈的泉水从60米高的悬崖陡壁倾泻而下，有“叠水如棉，不用弓弹花自散”的景象，似一批巨幅白绸在空中迎风飘舞，高峰悬岸间雪飞云涌，响声雷鸣，瀑布下又有温泉涌出，景观十分奇特。</span></span></span></p>', 0, 1, 0, 1, NULL, '德宏州芒市、陇川、瑞丽三县市结合处的莫里峡谷', '24.11593,97.98059', '0692-4143929,0692-4902174', '08:00-18:00', '35', 'JbhBYjNrhyHod2h3', '2024-05-15 20:55:30', '2024-05-23 14:00:49', 0) ON DUPLICATE KEY UPDATE
