INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '瑞丽总佛寺', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/19211715777832599_总佛寺.jpeg', '绕塔三圈
愿心所念皆如愿', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">总佛寺</span></span></span></strong></p><p class="MsoNormal"><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">绕塔三圈，愿心所念皆如愿</span></span></span></strong></p><p class="MsoNormal"></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">总佛寺是一座典型的南传佛教寺庙，由缅甸工匠建造，门窗雕刻精致，石柱涂红描金，屋顶金碧辉煌、雄伟壮观，与之遥相呼应的大金塔和小塔，以及瑞兽护法的雕像，展现了这座寺庙的独特魅力。总佛寺位置极佳，与缅甸只有一江之隔，不用任何望远镜，就能清晰看到缅甸的民房、大金塔等建筑。同时作为瑞丽的新晋地标，这里既能既能一览瑞丽全景，还可以欣赏绝美落日余晖。</span></span></span></p><p class="MsoNormal"></p>', 0, 1, 0, 2, NULL, '云南省德宏傣族景颇族自治州瑞丽市勐卯镇瑞丽大道总佛寺', '24.021278,97.912217', NULL, '08:00-18:00（全天）', '免费', 'XPPzPK2Hos68sIgu', '2024-05-15 20:57:34', '2024-05-23 11:58:51', 0) ON DUPLICATE KEY UPDATE
