INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '多宝之城', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/15601715778018370_多宝之城.jpg', '翡翠发烧友的淘宝地', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">多宝之城</span></span></span></strong></p><p class="MsoNormal"><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">翡翠发烧友的淘宝地</span></span></span></strong></p><p class="MsoNormal"></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">多宝之城拥有中缅边境最大的翡翠玉石成品交易市场，是旅游购物地标，游客购买翡翠的必到之地。在这里，看琳琅满目的翡翠制品，从精美的首饰到大型的摆件，应有尽有。在这里，市场内人头攒动，热闹非凡，商人们展示着他们的宝贝，买家们则在仔细挑选心仪的翡翠。在这里，形成了中缅互市特色+万平全品类珠宝市场+直播基地服务生态；</span></span></span></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">市场不仅是交易的场所，更是翡翠文化的集中体现地，你可以在这里了解翡翠的历史、鉴别方法以及各种工艺技巧，还能感受到浓厚的商业氛围和翡翠文化的独特韵味。</span></span></span></p>', 0, 1, 0, 2, NULL, '中国（云南）自由贸易试验区德宏片区瑞丽市瑞江路95号', '23.992342,97.869117', NULL, '08:00-18:00', '免费', 'ww2n3n0OuN5BxeNH', '2024-05-15 21:00:27', '2024-05-23 11:59:27', 0) ON DUPLICATE KEY UPDATE
