INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '姐东崃榕树王', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/14021715778320550_姐东徕榕树王.jpeg', '中国最早也是最大的藤编佛', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">姐东崃榕树王</span></span></span></strong></p><p class="MsoNormal"><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">灵性佛塔三绝汇聚</span></span></span></strong></p><p></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">姐东崃榕树王位于瑞丽最佳风水宝地、相传佛祖经过此处洒下了一滴清泉，清泉落地后化作了现在的百年古榕，人们为了感谢佛祖赐福，在榕树的旁边修建了佛塔。</span></span></span></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">寺中的大佛是中国最早也是最大的藤编佛，佛高6米，面色安详，静静的看护着一方水土。佛塔主塔高13.6米，小塔八个，东南亚风格，兼具古朴与妩娟。而最富传说的这棵百年古榕，依旧绿意融融。</span></span></span></p>', 0, 1, 0, 1, NULL, '德宏州瑞丽市XN02', '23.995769,97.817282', NULL, '08:00-18:00', '免费', 'IGfPx7T6uqUzml52', '2024-05-15 21:09:38', '2024-05-23 12:02:00', 0) ON DUPLICATE KEY UPDATE
