INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '畹町边关文化园', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/18971715778769478_畹町边关文化园.jpg', '记录着边境抗战名城的故事', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">畹町边关文化园</span></span></span></strong></p><p class="MsoNormal"><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">记录着边境抗战名城的故事</span></span></span></strong></p><p></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">畹町，系傣语，意为太阳当顶的地方，“畹町边关文化园”坐落于畹町城区中心，景区中心主路为著名的滇缅公路最后仅存的1.2公里路段，将建成涵盖抗战文化、和平外交文化、边关民族文化、珠宝翡翠文化相融合的高品位 、深内涵、广市场、优服务的边关文化产业园。园内有中缅友好纪念馆、古董车馆、中国远征军抗战纪念馆、世界珠宝馆、中缅民族民俗文化馆、世界钱币馆、世界邮票馆、记忆馆、民族古兵器馆、珍奇木艺馆等景点。</span></span></span></p>', 0, 1, 0, 5, NULL, '德宏州瑞丽市畹町镇国防街28号', '24.08045,98.07361', '13578238175', '全年9:00-18:00；17:40停止入场', '50', 'ZCoOHwvNU4grQxJ4', '2024-05-15 21:13:03', '2024-05-23 14:02:11', 0) ON DUPLICATE KEY UPDATE
