INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '大盈江', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/15401715780394125_大盈江.jpg', '“一片波光万里月 何人吹笛小桥头”', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">大盈江</span></span></span></strong></p><p class="MsoNormal"><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">“一片波光万里月 何人吹笛小桥头”</span></span></span></strong></p><p class="MsoNormal"></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">大盈江，境内最大的自然河流，也是盈江的母亲河，全长204公里，在盈江县境内长145公里。在数百里原始森林峡谷中穿行后来到盈江平原，流速减缓，江面扩宽，两岸是一望无垠的农田，竹树环合的村寨点缀其间，江岸有数千里的凤尾竹堤，江心时见绿色小岛，蓝天白云，翠竹绿岛映在悠悠的江面上，小船轻轻划过，悠扬的傣家情歌随风飘来，构成了一组别致的抒情诗，更称奇的是天神造就了“虎跳石”、“落水洞”和“奇石飞浪”奇观，惊心动魄，令人叫绝！</span></span></span></p>', 0, 1, 0, 0, NULL, '德宏州盈江县大盈江（高黎贡山南麓）', '24.679403,97.957161', NULL, '08:00-18:00（全天）', '免费', '45dDoZ4ffxB8IRmt', '2024-05-15 21:40:03', '2024-05-23 14:03:10', 0) ON DUPLICATE KEY UPDATE
