INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '诗蜜娃底', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/10421715780635384_诗蜜娃底.jpeg', '德宏州的小“香格里拉”', '<p class="MsoNormal"><strong><span style="letter-spacing:1px"><span style="line-height:1.75"><span style="font-size:20px">诗蜜娃底</span></span></span></strong></p><p class="MsoNormal"><strong><span style="letter-spacing:1px"><span style="line-height:1.75"><span style="font-size:16px">德宏州的小“香格里拉”</span></span></span></strong></p><p class="MsoNormal"> </p><p class="MsoNormal"><span style="letter-spacing:1px"><span style="line-height:1.75"><span style="font-size:16px">诗蜜娃底，傈僳族语意为“美丽的黄草坝”，广袤的草地、自在的牛羊，造型奇幻的大树间有条清澈的小河潺潺流过，快乐的傈僳人歌唱着放牧云间，精致迷人。诗蜜娃底，海拔约1000多米，冬季气候寒冷，面积约2平方公里，整个诗蜜娃底坝子地势平缓起，线条优美，坝中长满茂密的野草，牛马成群，一条小河从中穿过，良好的生态环境，使横穿于黄草坝的勐劈河清澈见底。这里四季皆有美景，冬季气候寒冷，白霜铺地，黄草戚戚；春天梨花如雪，山花漫野；夏天绿草没膝，凉风习习～这里是中外游客旅游度假的圣地，这里是不可多得的人间天堂。</span></span></span></p><p class="MsoNormal"></p>', 0, 1, 0, 3, NULL, '德宏州盈江县城以北43公里的苏典乡', '25.105627,97.936412', NULL, '08:00-18:00', '免费', 'DKC3XkxSo78TR76m', '2024-05-15 21:44:03', '2024-05-23 14:05:12', 0) ON DUPLICATE KEY UPDATE
