INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '南甸宣抚司署', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/13611715780707936_南甸宣抚司署.jpg', '傣族的“小故宫”', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">南甸宣抚司署</span></span></span></strong></p><p><span style="font-size:16px"><span style="letter-spacing:1px"><strong><span style="line-height:1.75">傣族的“小故宫</span></strong><span style="color:#000000"><span style="background-color:#ffffff">”</span></span></span></span></p><p></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">梁河南甸土司衙门曾是晚清至民国时期世袭南甸刀龚氏傣族土司日常办公和生活起居的场所，历经三代土司84年时间，占地超1万平方米，1998年被云南省政府列为省级第三批重点保护单位，是国内保存较完好的土司衙署。</span></span></span></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">“层层院井八方通，幢幢署阁殿中殿”梁河南甸土司衙门两侧为司主眷属居室，正堂两厢楼为司官、书房、账房办公处。其他三堂均有南北厢楼，供办公及职员居住用。全院有7拐24个花园及戏楼、小姐楼、佛堂、佣人住房、厨房、粮库、马房、军械房等建筑。</span></span></span></p>', 0, 1, 0, 3, NULL, '德宏州梁河县遮岛镇南甸路103号', '24.806912,98.297653', '0692-6161612；0692-6166603', '08:00-17:30，17:30停止进入', '20', 'EIZym7LWLun51FSq', '2024-05-15 21:46:04', '2024-05-23 14:07:46', 0) ON DUPLICATE KEY UPDATE
