INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '景罕佛塔', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/16861715780845107_景罕佛塔.jpg', '印度、缅甸、泰国佛教所公认的佛光宝地', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">景罕佛塔</span></span></span></strong></p><p class="MsoNormal"><strong><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">印度、缅甸、泰国佛教所公认的佛光宝地</span></span></span></strong></p><p class="MsoNormal"></p><p class="MsoNormal"><span style="font-size:16px"><span style="line-height:1.75"><span style="letter-spacing:1px">传说释加牟尼转世为玉兔时曾在该地出现，并有一段玉兔救人出火海的佳话；故此塔又称玉兔佛塔，景罕佛塔，傣语称为“广姆邦歹”，意为玉兔佛塔。“广姆”，傣语意为佛塔，“邦歹”，傣语意为玉兔。由一大八小共九座涂金笋状佛塔组成，为小乘佛教朝圣的地方，佛塔所建之处，地处坝子边沿，突起的一山丘，地势壮观。220多级台阶直上塔院。山体古树参天，林木遮天蔽日。登上佛塔，陇川坝子风光清晰在目，山后明镜似的水库，镶嵌其间，鸟语花香，格外幽静，每年傣历四月十四日（农历正月十四日）开始，举行盛大集会，历时三天，俗称“广卅（佛塔）摆”，游览者数万人。</span></span></span></p><p class="MsoNormal"></p>', 0, 1, 0, 3, NULL, '德宏州陇川县景罕镇东山顶', '24.24526,97.88462', NULL, '08:00-18:00全天', '免费', '8EOHFvKZhsiaOM82', '2024-05-15 21:47:54', '2024-05-23 14:08:36', 0) ON DUPLICATE KEY UPDATE
