INSERT INTO tourism_content (type, name, cover, intro, content, sort, status, isRecommend, readCount, album, address, coordinate, mobile, openTime, ticketPrice, sourceId, createTime, updateTime, isDelete) VALUES ('scenic', '章凤森林公园', 'https://6468-dhxmt-9gv6uup2086a6329-1325662932.tcb.qcloud.la/kit-cms-upload/2024-05-15/11801715780953246_章凤森林公园.jpg', '国家级森林公园', '<p class="MsoNormal"><strong><span style="line-height:1.75"><span style="letter-spacing:1px"><span style="font-size:20px">章凤森林公园</span></span></span></strong></p><p class="MsoNormal"><strong><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">国家级森林公园</span></span></span></strong></p><p class="MsoNormal"></p><p class="MsoNormal"><span style="line-height:1.75"><span style="font-size:16px"><span style="letter-spacing:1px">陇川森林公园是章凤国家森林公园的一部分，也是公南景颇园旅游景区的绿色走廊，处于陇川县城中心区域，面积近1000亩，由大小两个水库及周边坡地、原始森林、绿化构成了颇有层次感的景观，公园保留并增加植被景观近800亩，修建了环绕公园的观景台阶、亭台楼榭。在这里，感受休闲娱乐的生活。在这里，和大自然一起森呼吸。</span></span></span></p>', 0, 1, 0, 1, NULL, '云南省德宏傣族景颇族自治州陇川县215县道', '24.177534,97.82221', NULL, '08:00-18:00（全天）', '免费', 'pNZGZrCciAHwDHUe', '2024-05-15 21:49:20', '2024-05-23 14:09:25', 0) ON DUPLICATE KEY UPDATE
